-- Schema for Domain: maintenance | Business: Real Estate | Version: v1_ecm
-- Generated on: 2026-05-02 01:46:57

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `real_estate_ecm`.`maintenance` COMMENT 'Owns all facility operations and building services data — work orders, preventive maintenance schedules, HVAC and O&M records, tenant service requests, vendor dispatch, service contracts, and asset condition tracking. Sourced from Building Engines CMMS. Tracks CAPEX vs. OPEX classification for maintenance activities, OSHA safety compliance, and building equipment lifecycle.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`work_order` (
    `work_order_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for the work order record in the maintenance management system. Primary key for the work_order data product.',
    `amenity_id` BIGINT COMMENT 'Foreign key linking to property.amenity. Business justification: Amenity maintenance (pool, gym, rooftop terrace) generates work orders that must link to the specific amenity for amenity-level operating expense reporting and CAM cost allocation.',
    `asset_id` BIGINT COMMENT 'Reference to the property at which the work order is being executed. Links the maintenance activity to the physical asset for CAPEX/OPEX allocation and portfolio reporting.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Work order assignment to in-house technicians drives labor cost reporting, SLA accountability, and technician workload management. Real estate facilities teams track which employee executes each work ',
    `brokerage_deal_id` BIGINT COMMENT 'Foreign key linking to brokerage.deal. Business justification: TI (Tenant Improvement) work orders are executed against specific lease deals. Brokers and asset managers track work order completion against deal-committed TI scope and timelines. Domain experts expe',
    `building_asset_id` BIGINT COMMENT 'Reference to the specific building equipment or infrastructure asset (e.g., HVAC unit, elevator, boiler) against which the work order is raised. Supports equipment lifecycle tracking and O&M history.',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Work orders are scoped to a specific building for building-level maintenance cost allocation, SLA tracking, and compliance reporting. A property manager expects every work order to identify which buil',
    `capex_project_id` BIGINT COMMENT 'Foreign key linking to maintenance.capex_project. Business justification: Capital expenditure projects generate work orders for execution of major building improvements and equipment replacements. Linking work_order to capex_project enables CAPEX project cost tracking at th',
    `chart_of_accounts_id` BIGINT COMMENT 'Foreign key linking to finance.chart_of_accounts. Business justification: Work orders carry a gl_account_code for OpEx/CapEx classification and CAM recovery coding. A validated FK to chart_of_accounts ensures GL coding integrity for AP invoice matching, CAM reconciliation, ',
    `claim_id` BIGINT COMMENT 'Foreign key linking to insurance.claim. Business justification: Insurance claim-funded repair tracking: when a casualty loss (storm, flood, fire) triggers both an insurance claim and a remediation work order, property managers link the work order to the claim for ',
    `common_area_id` BIGINT COMMENT 'Foreign key linking to property.common_area. Business justification: Work orders for common area repairs (lobbies, corridors, restrooms) must link to the specific common area for CAM cost allocation and operating expense reporting. CAM reconciliation depends on this li',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Work orders for construction, renovation, or major repairs require building permits. Facilities managers track permit compliance per work order for certificate-of-occupancy and code enforcement purpos',
    `violation_id` BIGINT COMMENT 'Foreign key linking to compliance.violation. Business justification: Work orders are created to remediate compliance violations (OSHA citations, building code violations). Compliance officers tracking violation abatement deadlines need to link remediation work orders t',
    `construction_contract_id` BIGINT COMMENT 'Foreign key linking to development.construction_contract. Business justification: Warranty work orders executed under construction contract warranty provisions must reference the originating contract to enforce contractor recall obligations, track warranty claim costs against the c',
    `construction_permit_id` BIGINT COMMENT 'Foreign key linking to development.construction_permit. Business justification: Work orders for permitted maintenance activities (electrical panel replacement, structural repairs) must reference the governing construction permit for regulatory compliance and inspection sign-off. ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Work orders are charged to cost centers for property-level OpEx/CapEx tracking, NOI reporting, and budget variance analysis. RE property managers require cost center assignment on every work order to ',
    `dev_project_id` BIGINT COMMENT 'Foreign key linking to development.dev_project. Business justification: Post-construction warranty work orders and punch-list items are tracked against the originating development project. This link enables warranty period cost tracking, contractor performance reporting, ',
    `finance_budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: Work orders consume approved maintenance budgets. RE property managers track budget vs. actual spend at the work order level for monthly variance reporting and year-end CAM reconciliation. This link e',
    `owner_agreement_id` BIGINT COMMENT 'Foreign key linking to owner.owner_agreement. Business justification: Owner approval threshold enforcement: work orders exceeding the opex_approval_threshold or capex_approval_threshold in the governing owner agreement require owner sign-off. Property management systems',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to property.parcel. Business justification: Land/parcel maintenance work orders (drainage, environmental remediation, fence repair on vacant land) require parcel-level tracking for development-stage assets and land cost basis reporting.',
    `parking_id` BIGINT COMMENT 'Foreign key linking to property.parking. Business justification: Parking facility maintenance (gate repair, EV charger service, lighting) generates work orders that must link to the parking facility for parking-level cost tracking and operating expense reporting.',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Commercial real estate work orders are scoped to specific leasable spaces (suites) for CAM cost allocation and tenant billing. Space-level maintenance cost tracking is required for CAM reconciliation ',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Work orders triggered by regulatory mandates (OSHA-required remediation, fire code compliance, ADA upgrades) must be traceable to the governing obligation. Compliance officers use this link to demonst',
    `service_contract_id` BIGINT COMMENT 'Reference to the service contract under which this work order is executed. Enables contract utilization tracking, SLA enforcement, and vendor performance measurement.',
    `service_request_id` BIGINT COMMENT 'Foreign key linking to maintenance.service_request. Business justification: A work order is frequently generated in response to a tenant service request. This FK normalizes the originating service request relationship on the work order, enabling traceability from request subm',
    `sla_policy_id` BIGINT COMMENT 'Foreign key linking to maintenance.sla_policy. Business justification: work_order carries denormalized sla_response_target_hours and sla_completion_target_hours. These SLA targets are governed by sla_policy records. A FK to sla_policy normalizes the policy reference and ',
    `tenant_id` BIGINT COMMENT 'Reference to the tenant who submitted or is associated with the service request that generated this work order. Null for landlord-initiated or preventive maintenance work orders.',
    `tenant_occupancy_id` BIGINT COMMENT 'Foreign key linking to tenant.occupancy. Business justification: Tenant-billable work orders, TI completion verification, and move-out damage assessments must be linked to the specific occupancy. Property managers use this to track maintenance costs per occupancy p',
    `termination_id` BIGINT COMMENT 'Foreign key linking to lease.termination. Business justification: Lease termination restoration process: when a lease terminates, multiple work orders are created for space restoration, remediation, and condition assessment. Property managers track termination-spawn',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to property.inspection. Business justification: Property inspections trigger deficiency-remediation work orders. Linking work orders back to the triggering inspection supports inspection close-out tracking, regulatory compliance reporting, and audi',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Residential and commercial property management requires unit-level work order history for tenant billing, move-out inspections, and warranty tracking. Unit-level maintenance history is a standard prop',
    `vendor_id` BIGINT COMMENT 'Reference to the external contractor or service vendor dispatched to fulfill the work order. Null when work is performed by in-house maintenance staff.',
    `actual_completion_timestamp` TIMESTAMP COMMENT 'The actual date and time when the work order was fully completed and signed off. Used for SLA breach analysis, mean time to repair (MTTR) calculation, and vendor performance reporting.',
    `actual_labor_cost` DECIMAL(18,2) COMMENT 'The actual cost of labor incurred to complete the work order, including regular and overtime technician hours multiplied by applicable trade rates. Sourced from time-tracking entries in the CMMS or payroll system.',
    `actual_material_cost` DECIMAL(18,2) COMMENT 'The actual cost of parts, supplies, and materials consumed to complete the work order. Sourced from inventory consumption records or vendor invoices.',
    `actual_start_timestamp` TIMESTAMP COMMENT 'The actual date and time when work physically commenced on site. Compared against scheduled_start_date to measure dispatch punctuality and SLA adherence.',
    `actual_total_cost` DECIMAL(18,2) COMMENT 'The total actual cost of the work order combining labor and materials costs. Used for CAPEX/OPEX reporting, GL posting, and budget variance analysis. Equals actual_labor_cost + actual_material_cost plus any additional charges.',
    `capex_opex_classification` STRING COMMENT 'Financial classification of the work order as either Capital Expenditure (CAPEX) — costs that extend asset life or add value — or Operating Expenditure (OPEX) — routine maintenance and repair costs. Critical for financial reporting, GL coding, and FASB/IFRS compliance.. Valid values are `capex|opex`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the work order record was first created in the CMMS. Serves as the audit record creation timestamp and the baseline for SLA response time calculations.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this work order (estimated_cost, actual_labor_cost, actual_material_cost, actual_total_cost). Supports multi-currency portfolio operations.. Valid values are `^[A-Z]{3}$`',
    `estimated_cost` DECIMAL(18,2) COMMENT 'The pre-work estimated total cost of the work order including labor and materials, in the local operating currency. Used for budget approval workflows, CAPEX/OPEX forecasting, and purchase order generation.',
    `follow_up_required` BOOLEAN COMMENT 'Indicates whether additional work, a follow-up inspection, or a new work order is required after this work order is closed. True = a subsequent work order or inspection should be scheduled.',
    `gl_account_code` STRING COMMENT 'The General Ledger account code to which the work order costs are posted in the financial system. Enables direct integration with Yardi Voyager or SAP S/4HANA for CAPEX/OPEX cost allocation and financial reporting.',
    `labor_hours` DECIMAL(18,2) COMMENT 'Total number of technician labor hours expended on the work order, including regular and overtime hours. Used for workforce utilization analysis, trade cost benchmarking, and O&M reporting.',
    `location_detail` STRING COMMENT 'Specific location within the property where the work is to be performed (e.g., floor number, suite, room, mechanical room, rooftop). Supplements the property-level reference for precise dispatch and asset tracking.',
    `osha_safety_flag` BOOLEAN COMMENT 'Indicates whether this work order involves activities subject to OSHA safety regulations (e.g., confined space entry, lockout/tagout, working at heights, hazardous materials). True = OSHA-regulated activity requiring safety documentation and compliance sign-off.',
    `overtime_hours` DECIMAL(18,2) COMMENT 'Number of overtime labor hours charged to the work order. Separated from regular hours for payroll cost allocation, budget variance analysis, and emergency response cost tracking.',
    `permit_required` BOOLEAN COMMENT 'Indicates whether a building permit, hot work permit, or other regulatory permit is required before work can commence. True = permit must be obtained and documented prior to execution.',
    `pm_schedule_id` BIGINT COMMENT 'Reference to the preventive maintenance schedule that generated this work order, if applicable. Null for reactive or ad-hoc work orders. Links the work order to the PM program for compliance tracking and schedule adherence reporting.',
    `priority_level` STRING COMMENT 'Urgency classification assigned to the work order at creation or triage. Drives SLA target times, dispatch sequencing, and escalation rules. Critical typically indicates life-safety or building-critical system failure.. Valid values are `critical|high|medium|low|routine`',
    `purchase_order_number` STRING COMMENT 'The purchase order number issued to the vendor for this work order. Links the maintenance activity to the procurement and accounts payable workflow for invoice matching and payment processing.',
    `reported_timestamp` TIMESTAMP COMMENT 'The real-world date and time when the maintenance issue or service request was first reported by the tenant or building staff. May differ from created_timestamp if there is a lag in CMMS entry. The principal business event time for SLA measurement.',
    `requested_by` STRING COMMENT 'Name or identifier of the person who submitted the service request or initiated the work order — may be a tenant contact, property manager, or building engineer. Captured for accountability and tenant relationship management.',
    `resolution_notes` STRING COMMENT 'Free-text field capturing the technicians or vendors description of the work performed, root cause identified, parts replaced, and any follow-up actions recommended. Critical for asset maintenance history and recurring issue analysis.',
    `scheduled_completion_date` DATE COMMENT 'The planned date by which the work order is expected to be completed. Used as the SLA target date for on-time completion measurement and tenant communication.',
    `scheduled_start_date` DATE COMMENT 'The planned date on which work is scheduled to begin. Used for resource planning, vendor scheduling, and preventive maintenance calendar management.',
    `sla_breached` BOOLEAN COMMENT 'Indicates whether the work order exceeded its SLA completion target. True = SLA was breached; False = completed within SLA. Used for vendor performance scorecards, tenant reporting, and contract penalty triggers.',
    `sla_completion_target_hours` DECIMAL(18,2) COMMENT 'The contractually or operationally defined maximum number of hours within which the work order must be fully completed from the time of reporting. Used for SLA breach detection and vendor penalty calculations.',
    `sla_response_target_hours` DECIMAL(18,2) COMMENT 'The contractually or operationally defined maximum number of hours within which a technician or vendor must respond to the work order, based on priority level and service contract terms.',
    `source_system` STRING COMMENT 'Identifies the originating CMMS or operational system from which this work order record was sourced. Supports data lineage, multi-system integration reconciliation, and Silver layer provenance tracking.. Valid values are `building_engines|corrigo|angus|yardi|manual`',
    `tenant_billable` BOOLEAN COMMENT 'Indicates whether the cost of this work order is billable to the tenant under the terms of their lease (e.g., tenant-caused damage, above-standard services). True = costs to be included in tenant billing or CAM reconciliation.',
    `trade_category` STRING COMMENT 'The skilled trade or building systems discipline required to execute the work order (e.g., HVAC, electrical, plumbing). Used for vendor dispatch routing, workforce planning, and trade-level cost analysis. [ENUM-REF-CANDIDATE: hvac|electrical|plumbing|structural|elevator|fire_life_safety|janitorial|landscaping|general — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when the work order record was most recently modified in the CMMS. Used for change tracking, audit trails, and incremental data pipeline processing.',
    `warranty_claim` BOOLEAN COMMENT 'Indicates whether the work order is being executed under an active equipment or construction warranty. True = costs may be recoverable from the manufacturer or contractor; affects CAPEX/OPEX classification and cost recovery tracking.',
    `work_order_description` STRING COMMENT 'Free-text narrative describing the nature of the maintenance issue, the scope of work required, or the service request details as entered by the requestor or dispatcher.',
    `work_order_number` STRING COMMENT 'Externally visible, human-readable business identifier for the work order as assigned by the CMMS (e.g., Building Engines). Used in tenant communications, vendor dispatch, and audit trails.. Valid values are `^WO-[0-9]{4,10}$`',
    `work_order_status` STRING COMMENT 'Current lifecycle state of the work order. Tracks progression from creation through assignment, active execution, hold, completion, and final closure. Used for SLA breach analysis and operational dashboards. [ENUM-REF-CANDIDATE: draft|open|assigned|in_progress|on_hold|completed|cancelled|closed — promote to reference product]',
    `work_order_type` STRING COMMENT 'Classification of the work order by its operational nature. Corrective = reactive repair; Preventive = scheduled PM; Emergency = life-safety or critical system failure; Inspection = condition assessment; Capital Improvement = CAPEX project work; Tenant Improvement (TI) = tenant-specific fit-out or modification. [ENUM-REF-CANDIDATE: corrective|preventive|emergency|inspection|capital_improvement|tenant_improvement — promote to reference product]. Valid values are `corrective|preventive|emergency|inspection|capital_improvement|tenant_improvement`',
    CONSTRAINT pk_work_order PRIMARY KEY(`work_order_id`)
) COMMENT 'Core transactional entity representing a maintenance work order issued for a property or building asset. Captures the full lifecycle from creation through completion — including work type (corrective, preventive, emergency), priority level, CAPEX vs. OPEX classification, assigned trade/vendor, scheduled and actual completion dates, and safety compliance flags (OSHA, HSE, or equivalent jurisdiction-specific standards). Includes embedded cost line items for labor (technician hours, trade type, hourly rates, overtime) and materials (parts consumed, quantities, unit costs, supplier references). Tracks status transitions as an immutable audit trail for SLA breach analysis and compliance. Sourced from CMMS platforms (e.g., Building Engines, Corrigo, Angus). The primary operational record for all facility maintenance activity.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`service_request` (
    `service_request_id` BIGINT COMMENT 'Unique system-generated identifier for the tenant service request record. Primary key for the service_request data product in the maintenance domain.',
    `amenity_id` BIGINT COMMENT 'Foreign key linking to property.amenity. Business justification: Tenants submit service requests for amenity issues (broken gym equipment, pool closure). Amenity-level request tracking supports amenity operations management and tenant satisfaction KPIs.',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Service requests are submitted for a specific building. Building-level request volume, response-time, and tenant satisfaction reporting are standard property management KPIs requiring this link.',
    `common_area_id` BIGINT COMMENT 'Foreign key linking to property.common_area. Business justification: Service requests for common area issues (broken lobby door, elevator malfunction) must link to the specific common area for CAM cost allocation and common area maintenance performance reporting.',
    `employee_id` BIGINT COMMENT 'Identifier of the internal maintenance technician or engineer assigned to fulfill the service request. May be null if the request is dispatched to an external vendor.',
    `lease_agreement_id` BIGINT COMMENT 'Identifier of the active lease associated with the tenant and suite at the time of the service request. Used for CAM charge-back allocation and lease-level reporting.',
    `parking_id` BIGINT COMMENT 'Foreign key linking to property.parking. Business justification: Tenants submit service requests for parking issues (broken gate, damaged space markings). Parking-level request tracking supports parking operations management and tenant satisfaction reporting.',
    `asset_id` BIGINT COMMENT 'Identifier of the property (building or complex) where the service request originated. Links to the property master record.',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Commercial tenants submit service requests referencing their specific suite/space. Space-level request tracking supports CAM billing, tenant satisfaction reporting, and lease administration.',
    `sla_policy_id` BIGINT COMMENT 'Foreign key linking to maintenance.sla_policy. Business justification: service_request carries denormalized sla_response_target_hours and sla_resolution_target_hours. These SLA targets are governed by sla_policy records. A FK to sla_policy normalizes the policy reference',
    `tenant_contact_id` BIGINT COMMENT 'Foreign key linking to tenant.tenant_contact. Business justification: service_request stores tenant_contact_name, tenant_contact_phone, tenant_contact_email as denormalized plain columns. A proper FK to tenant_contact enforces referential integrity, eliminates data dupl',
    `tenant_id` BIGINT COMMENT 'Identifier of the tenant who submitted the service request. Supports tenant relationship management, SLA tracking, and CAM charge-back attribution.',
    `tenant_occupancy_id` BIGINT COMMENT 'Foreign key linking to tenant.occupancy. Business justification: Service requests must be tied to an active occupancy for move-in/move-out condition reporting, SLA compliance tracking by occupancy type, and tenant satisfaction scoring. Property managers use this li',
    `unit_id` BIGINT COMMENT 'Identifier of the specific suite or unit within the property from which the service request was submitted. Enables location-level maintenance tracking and CAM cost allocation.',
    `acknowledged_timestamp` TIMESTAMP COMMENT 'Date and time when the property management team or assigned technician formally acknowledged receipt of the service request. Used to measure SLA response time compliance.',
    `actual_cost` DECIMAL(18,2) COMMENT 'Actual cost incurred to fulfill the service request upon completion, in the local operating currency. Populated from work order actuals or vendor invoice. Used for CAM reconciliation, OPEX/CAPEX reporting, and budget variance analysis.',
    `cam_chargeable` BOOLEAN COMMENT 'Indicates whether the cost of fulfilling this service request is eligible for CAM charge-back to the tenant under the terms of their lease (True = CAM chargeable). Drives accounts receivable and CAM reconciliation processes.',
    `capex_opex_classification` STRING COMMENT 'Financial classification of the maintenance activity as either capital expenditure (CAPEX — asset improvement or replacement) or operating expenditure (OPEX — routine repair and maintenance). Critical for financial reporting, fixed asset accounting, and tax treatment.. Valid values are `CAPEX|OPEX|undetermined`',
    `closed_timestamp` TIMESTAMP COMMENT 'Date and time when the service request was formally closed after tenant confirmation or automatic closure policy. May differ from resolved_timestamp if a tenant sign-off or satisfaction confirmation period applies.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the service request record was first created in the system. May differ from submitted_timestamp if the record was entered retrospectively by property management staff.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to the estimated_cost and actual_cost fields (e.g., USD, CAD, GBP). Supports multi-currency portfolio operations.. Valid values are `^[A-Z]{3}$`',
    `estimated_cost` DECIMAL(18,2) COMMENT 'Estimated cost to fulfill the service request, in the local operating currency. Used for budget pre-approval workflows, CAPEX vs OPEX classification, and CAM charge-back estimation.',
    `floor_number` STRING COMMENT 'Floor or level within the building where the service request issue is located. Used for technician dispatch routing and building-level maintenance analytics.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when the service request record was most recently modified. Used for change tracking, audit trails, and incremental data pipeline processing.',
    `location_detail` STRING COMMENT 'Free-text description of the specific location within the suite or building where the issue is occurring (e.g., northwest corner office, mens restroom 3rd floor, server room). Supplements the suite_id with precise on-site location context.',
    `osha_safety_flag` BOOLEAN COMMENT 'Indicates whether the service request involves a safety hazard or OSHA-reportable condition (True = safety concern present). Triggers mandatory safety protocols, escalation procedures, and regulatory reporting obligations.',
    `recurrence_flag` BOOLEAN COMMENT 'Indicates whether this service request is a recurrence of a previously reported issue at the same location or for the same asset (True = recurring issue). Supports root cause analysis, asset lifecycle decisions, and preventive maintenance program adjustments.',
    `request_category` STRING COMMENT 'Primary classification of the service request by building system or trade (e.g., HVAC, plumbing, electrical, janitorial, access control). Drives routing to the appropriate technician or vendor and supports CAM charge-back categorization. [ENUM-REF-CANDIDATE: HVAC|plumbing|electrical|janitorial|access|structural|elevator|fire_safety|pest_control|general — promote to reference product]',
    `request_description` STRING COMMENT 'Free-text narrative provided by the tenant describing the issue, fault, or service needed. Captures the tenants own words for context and is used by technicians to prepare for the job.',
    `request_number` STRING COMMENT 'Externally visible, human-readable reference number assigned to the service request at submission (e.g., SR-2024-000123). Used by tenants and property management staff to track and reference the request across communications and portals.. Valid values are `^SR-[0-9]{4}-[0-9]{6}$`',
    `request_status` STRING COMMENT 'Current lifecycle status of the service request workflow. Tracks progression from tenant submission through resolution and closure. [ENUM-REF-CANDIDATE: submitted|acknowledged|in_progress|on_hold|resolved|closed|cancelled — promote to reference product]',
    `request_subcategory` STRING COMMENT 'Secondary classification providing more granular detail within the request category (e.g., within HVAC: thermostat, air handler, ductwork; within plumbing: leak, drain, fixture). Supports detailed maintenance analytics and vendor specialization routing.',
    `resolution_notes` STRING COMMENT 'Free-text notes entered by the technician or property manager describing the work performed, root cause identified, and resolution achieved. Supports maintenance history and recurring issue analysis.',
    `resolved_timestamp` TIMESTAMP COMMENT 'Date and time when the service request issue was fully resolved and the work was completed. Used to calculate actual resolution time against SLA resolution target.',
    `sla_resolution_breached` BOOLEAN COMMENT 'Indicates whether the SLA resolution target was breached for this service request (True = breach occurred). Populated at closure. Supports SLA compliance reporting and potential lease penalty calculations.',
    `sla_resolution_target_hours` DECIMAL(18,2) COMMENT 'The contracted or policy-defined maximum number of hours within which the service request must be fully resolved, based on urgency level and lease SLA terms. Distinct from response target — this measures full closure.',
    `sla_response_breached` BOOLEAN COMMENT 'Indicates whether the SLA response target was breached for this service request (True = breach occurred). Populated at acknowledgement or closure. Supports SLA compliance reporting and tenant relationship management.',
    `sla_response_target_hours` DECIMAL(18,2) COMMENT 'The contracted or policy-defined maximum number of hours within which the property management team must acknowledge or respond to the service request, based on urgency level and lease SLA terms.',
    `source_system_ref` STRING COMMENT 'The native identifier of this service request record in the originating operational system (Building Engines CMMS). Enables traceability and reconciliation between the lakehouse silver layer and the source system of record.',
    `submission_channel` STRING COMMENT 'The channel or interface through which the tenant submitted the service request (e.g., tenant portal, mobile app, help desk call, email). Supports channel analytics and tenant engagement reporting.. Valid values are `tenant_portal|mobile_app|help_desk|email|phone|in_person`',
    `submitted_timestamp` TIMESTAMP COMMENT 'Date and time when the tenant submitted the service request through the portal, help desk, or mobile app. This is the principal business event timestamp and the anchor for all SLA calculations.',
    `tenant_feedback_notes` STRING COMMENT 'Free-text comments provided by the tenant in the post-resolution satisfaction survey. Captures qualitative feedback for property management quality improvement and tenant retention analysis.',
    `tenant_satisfaction_score` DECIMAL(18,2) COMMENT 'Numeric satisfaction rating provided by the tenant upon closure of the service request, typically on a 1–5 or 1–10 scale. Supports tenant relationship management KPIs and property management performance reviews.',
    `urgency_level` STRING COMMENT 'Tenant-declared or property-manager-assessed urgency of the service request. Determines SLA tier assignment and dispatch prioritization. Emergency requests may trigger immediate vendor dispatch and OSHA safety protocols.. Valid values are `emergency|urgent|high|normal|low`',
    `work_order_count` STRING COMMENT 'Number of work orders spawned from this service request. A single service request may generate multiple work orders for different trades or vendors. Supports complexity analysis and operational reporting.',
    `work_started_timestamp` TIMESTAMP COMMENT 'Date and time when physical work or active remediation on the service request commenced. Marks the transition from dispatched/acknowledged to in-progress status.',
    CONSTRAINT pk_service_request PRIMARY KEY(`service_request_id`)
) COMMENT 'Tenant-initiated service request submitted through a tenant portal, help desk, or mobile app. Captures the originating tenant, property, suite, request category (HVAC, plumbing, electrical, janitorial, access), description, urgency, submission timestamp, SLA target response and resolution times, and current status. Distinct from a work order — a service request is the tenant-facing intake record that may spawn one or more work orders. Supports tenant relationship management and CAM charge-back tracking.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`pm_schedule` (
    `pm_schedule_id` BIGINT COMMENT 'Unique system-generated identifier for the preventive maintenance schedule record. Primary key for the pm_schedule data product in the maintenance domain.',
    `amenity_id` BIGINT COMMENT 'Foreign key linking to property.amenity. Business justification: Amenity PM schedules (pool chemical checks, gym equipment inspection, seasonal opening/closing) are organized by amenity. Amenity-level PM compliance supports liability management and tenant satisfact',
    `building_asset_id` BIGINT COMMENT 'Foreign key linking to maintenance.building_asset. Business justification: PM schedules are often defined for specific building equipment assets (HVAC units, elevators, fire suppression systems, etc.) in addition to property-level assets. The pm_schedule table currently only',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Preventive maintenance schedules are organized by building (e.g., HVAC PM for Building A). Building-level PM compliance reporting and certificate tracking are standard property management KPIs.',
    `common_area_id` BIGINT COMMENT 'Foreign key linking to property.common_area. Business justification: Common area PM schedules (cleaning, fire safety checks, HVAC) are organized by common area. Common area-level PM compliance reporting supports CAM cost justification and regulatory compliance.',
    `green_certification_id` BIGINT COMMENT 'Foreign key linking to compliance.green_certification. Business justification: LEED O+M and BREEAM In-Use certifications require specific maintenance protocols (filter changes, commissioning, water treatment). Sustainability managers link PM schedules to the green certification ',
    `contractor_id` BIGINT COMMENT 'Reference to the contracted vendor or service provider assigned to execute this PM schedule. Used for vendor dispatch, service contract linkage, and AP processing.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: PM schedules carry estimated costs budgeted by cost center for annual maintenance planning. RE property managers use cost center assignment on PM schedules for maintenance budget preparation, CAM expe',
    `dev_project_id` BIGINT COMMENT 'Foreign key linking to development.dev_project. Business justification: Preventive maintenance schedules are established during project handover from development to operations. Linking pm_schedule to dev_project enables warranty-period PM compliance tracking and ensures m',
    `employee_id` BIGINT COMMENT 'Reference to the internal facilities technician or engineer assigned as the primary responsible party for executing this PM schedule. Used for workforce scheduling and accountability tracking.',
    `work_order_id` BIGINT COMMENT 'Reference to the most recently generated and closed work order for this PM schedule. Provides a direct link to the last execution record for audit and compliance verification.',
    `parking_id` BIGINT COMMENT 'Foreign key linking to property.parking. Business justification: Parking facility PM schedules (sweeping, lighting checks, gate maintenance) are organized by parking facility. Parking-level PM compliance is standard in property operations management.',
    `asset_id` BIGINT COMMENT 'Reference to the building asset or equipment item this PM schedule governs (e.g., HVAC unit, elevator, fire panel, generator). Links to the asset master in the Fixed Assets or CMMS system.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: PM schedules for regulated equipment (elevators, boilers, fire suppression) are mandated by specific regulatory obligations. Compliance officers link PM schedules to obligations to verify maintenance ',
    `service_contract_id` BIGINT COMMENT 'Reference to the vendor service contract under which this PM schedule is executed. Links PM activities to contract terms, SLAs, and AP payment obligations.',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Residential PM schedules (annual smoke detector checks, HVAC filter replacements per unit) are scoped to specific units. Unit-level PM compliance tracking is required for habitability regulations and ',
    `advance_notice_days` STRING COMMENT 'Number of days before the next_due_date that the CMMS should generate the work order or send a notification alert. Allows time for parts procurement, vendor scheduling, and tenant notification.',
    `asset_system_type` STRING COMMENT 'Classification of the building system or equipment category this PM schedule covers (e.g., HVAC, Electrical, Plumbing, Fire & Life Safety, Elevator, BMS, Generator, Roofing). Supports portfolio-level maintenance analytics. [ENUM-REF-CANDIDATE: HVAC|Electrical|Plumbing|Fire & Life Safety|Elevator|BMS|Generator|Roofing|Structural — promote to reference product]',
    `breeam_relevant` BOOLEAN COMMENT 'Indicates whether this PM schedule contributes to BREEAM certification maintenance for the property. Supports international green building compliance tracking alongside LEED.',
    `building_floor_level` STRING COMMENT 'Floor or level within the building where the asset subject to this PM schedule is located (e.g., B1, L3, Roof). Supports technician navigation and spatial maintenance reporting.',
    `compliance_flag` BOOLEAN COMMENT 'Indicates whether this PM schedule is mandated by a regulatory, safety, or warranty compliance requirement (OSHA, HSE, LEED, manufacturer warranty). True = compliance-driven; False = discretionary maintenance.',
    `cost_classification` STRING COMMENT 'Accounting classification of the maintenance activity as CAPEX (capital expenditure — extends asset life or adds value) or OPEX (operating expenditure — routine maintenance). Critical for financial reporting, GL coding, and REIT compliance.. Valid values are `OPEX|CAPEX|mixed`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this PM schedule record was first created in the CMMS. Supports audit trail, data lineage, and Silver layer ingestion tracking.',
    `effective_end_date` DATE COMMENT 'The date on which this PM schedule expires or is decommissioned. Null for open-ended schedules. Used to sunset PM programs when assets are retired or service contracts expire.',
    `effective_start_date` DATE COMMENT 'The date from which this PM schedule becomes active and begins generating work orders. Typically aligned with asset commissioning date, lease commencement, or service contract start.',
    `esg_category` STRING COMMENT 'ESG classification of the PM activity indicating its environmental impact category. Used for sustainability reporting, LEED compliance, and GRESB (Global Real Estate Sustainability Benchmark) submissions.. Valid values are `energy|water|waste|emissions|indoor_air|other`',
    `estimated_labor_cost` DECIMAL(18,2) COMMENT 'Estimated cost of labor per PM execution in the local currency. Used for OPEX budgeting, CAPEX vs. OPEX classification, and service contract benchmarking.',
    `estimated_labor_hours` DECIMAL(18,2) COMMENT 'Estimated number of labor hours required to complete one execution of this PM task. Used for workforce scheduling, OPEX budgeting, and service contract cost estimation.',
    `estimated_parts_cost` DECIMAL(18,2) COMMENT 'Estimated cost of materials and replacement parts required per PM execution. Used for OPEX/CAPEX budgeting and procurement planning.',
    `frequency_interval` STRING COMMENT 'Numeric multiplier applied to the frequency_type to define the exact recurrence (e.g., frequency_type=weekly with frequency_interval=2 means every 2 weeks). Allows sub-type granularity beyond standard frequency buckets.',
    `frequency_type` STRING COMMENT 'Recurrence interval for the PM schedule defining how often the maintenance task must be performed. Drives automated work order generation cadence in the CMMS.. Valid values are `daily|weekly|monthly|quarterly|semi_annual|annual`',
    `gl_account_code` STRING COMMENT 'General Ledger account code to which PM-related costs are posted. Ensures correct financial classification and supports OPEX/CAPEX reporting in Yardi Voyager and SAP S/4HANA.',
    `inspection_required` BOOLEAN COMMENT 'Indicates whether a formal inspection report or third-party certification is required upon completion of this PM task (e.g., elevator annual inspection certificate, fire suppression test report).',
    `last_completed_date` DATE COMMENT 'The most recent date on which the PM task was fully executed and closed. Used to calculate next_due_date and to assess compliance with the maintenance schedule.',
    `leed_required` BOOLEAN COMMENT 'Indicates whether this PM task is required to maintain LEED certification for the property. Supports ESG reporting and green building compliance tracking.',
    `location_description` STRING COMMENT 'Detailed physical location description of the asset within the building (e.g., Mechanical Room 3B, East Wall, Rooftop AHU-7 adjacent to cooling tower). Aids technician dispatch and asset identification.',
    `next_due_date` DATE COMMENT 'The next calendar date on which a work order must be generated and the PM task executed. Recalculated automatically after each completion. Critical for scheduling and compliance tracking.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, special instructions, or contextual information relevant to this PM schedule (e.g., Coordinate with tenant 48 hours in advance, Requires roof access key from security).',
    `osha_required` BOOLEAN COMMENT 'Indicates whether this PM task is specifically required under OSHA regulations (e.g., lockout/tagout, confined space, fire suppression). Drives safety compliance reporting and audit trails.',
    `permit_required` BOOLEAN COMMENT 'Indicates whether a municipal or regulatory permit is required before executing this PM task (e.g., hot work permit, confined space entry permit, electrical work permit). Supports OSHA and local code compliance.',
    `priority_level` STRING COMMENT 'Business priority assigned to this PM schedule, used to triage scheduling conflicts and resource allocation. critical typically applies to life-safety systems (fire suppression, elevators, emergency generators).. Valid values are `critical|high|medium|low`',
    `required_parts_list` STRING COMMENT 'Comma-separated list or description of parts, materials, and consumables required to execute this PM task (e.g., MERV-13 filter 20x20x2, belt drive V-belt, lubricant grease). Used for inventory pre-staging and procurement.',
    `schedule_name` STRING COMMENT 'Human-readable name or title of the PM schedule (e.g., Annual HVAC Filter Replacement – Tower A, Monthly Fire Suppression Inspection). Used for display in CMMS dashboards and reporting.',
    `schedule_number` STRING COMMENT 'Externally-known alphanumeric identifier for the PM schedule, used in work order generation, vendor communications, and CMMS references. Sourced from Building Engines PM module.. Valid values are `^PM-[A-Z0-9]{3,20}$`',
    `schedule_status` STRING COMMENT 'Current lifecycle state of the PM schedule. active means the schedule is generating work orders; suspended means temporarily paused (e.g., asset offline); archived means decommissioned.. Valid values are `active|inactive|suspended|draft|archived`',
    `task_checklist_template` STRING COMMENT 'Name or code reference to the standardized task checklist template used for this PM schedule. The template defines the step-by-step inspection and maintenance procedures to be followed during execution.',
    `task_description` STRING COMMENT 'Detailed narrative description of the maintenance work to be performed under this PM schedule. Includes scope of work, inspection points, and any special instructions for the assigned technician or vendor.',
    `trade_category` STRING COMMENT 'The skilled trade or discipline responsible for executing this PM (e.g., HVAC, Electrical, Plumbing, Fire & Life Safety, Elevator, Roofing, Landscaping, Janitorial). Drives technician assignment and vendor dispatch. [ENUM-REF-CANDIDATE: HVAC|Electrical|Plumbing|Fire & Life Safety|Elevator|Roofing|Landscaping|Janitorial|General — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this PM schedule record. Used for change tracking, incremental data loads, and audit compliance.',
    `warranty_required` BOOLEAN COMMENT 'Indicates whether this PM task is required to maintain the manufacturers equipment warranty. Failure to execute may void warranty coverage and expose the organization to uninsured repair costs.',
    `work_order_auto_generate` BOOLEAN COMMENT 'Indicates whether the CMMS should automatically generate a work order when the next_due_date is reached. If False, a facilities manager must manually trigger work order creation.',
    CONSTRAINT pk_pm_schedule PRIMARY KEY(`pm_schedule_id`)
) COMMENT 'Preventive Maintenance (PM) schedule master record defining the recurring maintenance program for a building asset or equipment item. Stores the PM frequency (daily, weekly, monthly, annual), task checklist template, assigned trade category, estimated labor hours, required parts, next due date, last completed date, and compliance flag (OSHA/HSE, LEED, manufacturer warranty). Drives automated work order generation in the CMMS. Distinct from a work order — this is the standing schedule, not the execution record.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`building_asset` (
    `building_asset_id` BIGINT COMMENT 'Unique surrogate identifier for each physical building equipment or infrastructure asset record in the maintenance master registry. Primary key for the building_asset data product.',
    `amenity_id` BIGINT COMMENT 'Foreign key linking to property.amenity. Business justification: Amenity-specific assets (pool pump, gym equipment, AV system in conference room) are tracked against specific amenities. Amenity asset register supports replacement planning and amenity operating cost',
    `design_document_id` BIGINT COMMENT 'Foreign key linking to development.design_document. Business justification: Building assets must be linked to their as-built design documents for O&M manual compliance, equipment replacement specifications, and regulatory inspections. Real estate facility managers routinely r',
    `asset_id` BIGINT COMMENT 'Reference to the property or building where this asset is physically installed and maintained. Links the asset to its parent facility in the property master.',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Building assets (HVAC units, elevators, fire panels) are physically located in a specific building. Building-level asset register, replacement cost reporting, and capital planning require this link. b',
    `chart_of_accounts_id` BIGINT COMMENT 'Foreign key linking to finance.chart_of_accounts. Business justification: building_asset.gl_asset_account_code is a denormalized reference to the chart_of_accounts GL asset account. A validated FK supports fixed asset capitalization entries, depreciation posting, and asset ',
    `common_area_id` BIGINT COMMENT 'Foreign key linking to property.common_area. Business justification: Common area assets (lobby HVAC, corridor lighting, elevator) are tracked against specific common areas. CAM cost allocation and asset replacement planning require linking building assets to common are',
    `construction_contract_id` BIGINT COMMENT 'Foreign key linking to development.construction_contract. Business justification: Building assets carry labor warranties tied to the construction contract under which they were installed. Linking building_asset to construction_contract enables warranty claim processing, contractor ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Building assets are assigned to cost centers for depreciation allocation and maintenance cost tracking. RE controllers require cost center on building assets for depreciation posting, capital expendit',
    `dev_project_id` BIGINT COMMENT 'Foreign key linking to development.dev_project. Business justification: Building assets (HVAC, elevators, fire suppression) are installed during development projects. Linking building_asset to dev_project enables warranty period tracking, as-built documentation retrieval,',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Every capitalized building asset has a corresponding fixed asset record for depreciation and book value tracking. RE asset managers require the physical-to-financial asset link for depreciation schedu',
    `parking_id` BIGINT COMMENT 'Foreign key linking to property.parking. Business justification: Parking-specific assets (gate motors, EV chargers, lighting systems) are tracked against the parking facility. Parking asset register and maintenance cost reporting require this link for capital plann',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Commercial spaces may have dedicated assets (tenant-specific HVAC zone, dedicated electrical panel). Space-level asset tracking supports TI cost allocation, CAM reconciliation, and lease-end asset dis',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Building assets (elevators, boilers, fire suppression systems, pressure vessels) are subject to specific regulatory obligations (annual certifications, operating permits). Compliance officers maintain',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Unit-specific assets (in-unit HVAC, water heater, appliances in residential) are tracked at the unit level. Unit-level asset register is required for tenant move-out inspections, warranty tracking, an',
    `asset_category` STRING COMMENT 'High-level classification grouping of the asset type used for portfolio-level O&M reporting and CAPEX planning (e.g., HVAC, Electrical, Plumbing, Vertical Transportation, Fire Life Safety, Roofing, Structural, Generator, Building Envelope). [ENUM-REF-CANDIDATE: HVAC|Electrical|Plumbing|Vertical Transportation|Fire Life Safety|Roofing|Structural|Generator|Building Envelope|Other — promote to reference product]',
    `asset_criticality` STRING COMMENT 'Business criticality classification of the asset based on its impact on building operations, tenant services, and life safety if it fails. critical = life safety or total building operations impact; high = major tenant disruption; medium = partial service impact; low = minimal operational impact. Drives work order priority and PM frequency.. Valid values are `critical|high|medium|low`',
    `asset_status` STRING COMMENT 'Current operational lifecycle status of the asset. active = in normal service; inactive = temporarily out of service; decommissioned = permanently removed; under_repair = currently being serviced; pending_replacement = approved for capital replacement.. Valid values are `active|inactive|decommissioned|under_repair|pending_replacement`',
    `asset_tag` STRING COMMENT 'Externally-visible physical label or barcode affixed to the asset for field identification during inspections, work orders, and preventive maintenance rounds. Unique within a property. Sourced from Building Engines asset registry.. Valid values are `^[A-Z0-9-]{3,30}$`',
    `asset_type` STRING COMMENT 'Specific equipment type within the asset category (e.g., Air Handling Unit, Chiller, Boiler, Fire Suppression Sprinkler System, Hydraulic Elevator, Standby Generator). Drives preventive maintenance task templates in Building Engines. [ENUM-REF-CANDIDATE: promote to reference product given high cardinality]',
    `bim_reference_code` STRING COMMENT 'Unique object identifier linking this asset to its corresponding component in the Building Information Modeling (BIM) model (e.g., Revit GUID or IFC GlobalId). Enables spatial visualization, clash detection, and digital twin integration.',
    `capex_opex_classification` STRING COMMENT 'Accounting classification indicating whether maintenance and replacement activities for this asset are capitalized (CAPEX) or expensed (OPEX) per FASB ASC 360 and internal accounting policy. mixed applies to assets with both capital and operating components (e.g., partial HVAC overhaul).. Valid values are `capex|opex|mixed`',
    `condition_rating` STRING COMMENT 'Current physical condition rating of the asset as assessed during the most recent condition assessment. Drives prioritization of CAPEX replacement and preventive maintenance frequency. Scale: excellent=new/like-new; good=minor wear; fair=moderate wear; poor=significant deterioration; critical=imminent failure risk.. Valid values are `excellent|good|fair|poor|critical`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this asset record was first created in the Building Engines CMMS and ingested into the maintenance domain data product. Supports audit trail and data lineage tracking.',
    `depreciation_method` STRING COMMENT 'Accounting depreciation method applied to this asset for financial reporting purposes. straight_line is most common for real estate equipment. Aligns with Yardi Voyager Fixed Assets and SAP S/4HANA asset accounting configuration.. Valid values are `straight_line|declining_balance|units_of_production|sum_of_years`',
    `energy_efficiency_rating` STRING COMMENT 'Manufacturer-specified energy efficiency rating or metric for the asset (e.g., SEER rating for HVAC, EER, COP, kW/ton). Null if not applicable. Used for ESG reporting, LEED documentation, and energy benchmarking under EPA ENERGY STAR.',
    `energy_rated` BOOLEAN COMMENT 'Indicates whether this asset has an energy efficiency rating or certification (e.g., ENERGY STAR, LEED-qualifying equipment). Supports ESG reporting, LEED certification tracking, and sustainability benchmarking.',
    `extended_warranty_expiry` DATE COMMENT 'Date on which any purchased extended warranty coverage expires. Null if no extended warranty is in place. Used alongside manufacturer warranty to determine warranty claim eligibility for repair work orders.',
    `floor_location` STRING COMMENT 'Floor or level within the building where the asset is physically located (e.g., B1, Ground, 3, Rooftop, Mechanical Room 2). Used for field technician dispatch and Building Information Modeling (BIM) spatial reference.',
    `installation_date` DATE COMMENT 'Date the asset was physically installed and commissioned at the property. Anchors useful life calculations, warranty start dates, and CAPEX replacement year projections.',
    `is_tenant_owned` BOOLEAN COMMENT 'Indicates whether the asset is owned by a tenant rather than the property owner. Tenant-owned assets are tracked for maintenance coordination but excluded from owner CAPEX planning and depreciation schedules. Relevant for Tenant Improvement (TI) assets.',
    `labor_warranty_expiry` DATE COMMENT 'Date on which the installation contractors labor warranty expires. Covers defects in workmanship separate from equipment manufacturer warranty. Null if no labor warranty applies.',
    `last_condition_assessment_date` DATE COMMENT 'Date of the most recent formal property condition assessment (PCA) or engineering inspection that produced the current condition rating. Indicates data freshness for capital planning purposes.',
    `last_pm_date` DATE COMMENT 'Date the most recent preventive maintenance (PM) service was completed on this asset. Used to calculate next scheduled PM date and identify overdue maintenance items.',
    `last_regulatory_inspection_date` DATE COMMENT 'Date of the most recent mandatory regulatory inspection or certification for this asset. Null if regulatory_inspection_required is false. Used for compliance reporting and COO maintenance.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this asset record in the source system or data product. Used for incremental data pipeline processing and change data capture (CDC) in the Databricks Silver layer.',
    `last_warranty_claim_date` DATE COMMENT 'Date of the most recent warranty claim submitted for this asset. Null if no warranty claims have been filed. Used to track warranty utilization and vendor responsiveness.',
    `manufacturer` STRING COMMENT 'Name of the original equipment manufacturer (OEM) of the asset. Used for warranty claims, spare parts procurement, and vendor dispatch coordination.',
    `manufacturer_warranty_expiry` DATE COMMENT 'Date on which the original equipment manufacturer (OEM) warranty expires. After this date, repair costs are no longer recoverable from the manufacturer. Critical for work order cost routing decisions.',
    `model_number` STRING COMMENT 'Manufacturer-assigned model or part number for the asset. Required for ordering replacement parts, scheduling OEM-certified service, and cross-referencing BIM component libraries.',
    `next_pm_due_date` DATE COMMENT 'Scheduled due date for the next preventive maintenance (PM) service on this asset, calculated from last PM date and PM schedule frequency. Drives work order scheduling and compliance reporting in Building Engines.',
    `pm_schedule_frequency` STRING COMMENT 'Required frequency of preventive maintenance (PM) inspections and servicing for this asset as defined in the O&M program. Drives automated PM work order generation in Building Engines CMMS.. Valid values are `daily|weekly|monthly|quarterly|semi_annual|annual`',
    `purchase_cost` DECIMAL(18,2) COMMENT 'Original acquisition cost of the asset in USD at time of purchase or installation. Used as the cost basis for fixed asset depreciation schedules in Yardi Voyager and SAP S/4HANA Fixed Assets module.',
    `recommended_replacement_year` STRING COMMENT 'Calendar year in which the asset is recommended for capital replacement based on condition assessment findings and remaining useful life estimate. Used to populate CAPEX schedules in Argus Enterprise and SAP S/4HANA project systems.',
    `refrigerant_type` STRING COMMENT 'Type of refrigerant used in HVAC or cooling equipment (e.g., R-410A, R-22, R-134a, R-32). Null for non-refrigerant assets. Required for EPA Section 608 refrigerant management compliance and ESG greenhouse gas reporting.',
    `regulatory_inspection_expiry` DATE COMMENT 'Date on which the current regulatory inspection certificate or permit expires. Null if not applicable. Expiry triggers mandatory re-inspection scheduling to maintain compliance and avoid operational shutdowns.',
    `regulatory_inspection_required` BOOLEAN COMMENT 'Indicates whether this asset is subject to mandatory regulatory inspection and certification (e.g., elevators, boilers, fire suppression systems, pressure vessels). True triggers compliance tracking and certificate of occupancy (COO) dependencies.',
    `remaining_useful_life_years` DECIMAL(18,2) COMMENT 'Estimated number of years remaining before the asset requires capital replacement, as determined by the most recent condition assessment. Decimal precision supports mid-year estimates. Key input for CAPEX reserve modeling and Argus Enterprise cash flow projections.',
    `replacement_cost` DECIMAL(18,2) COMMENT 'Current estimated cost in USD to replace the asset with a new equivalent unit, inclusive of equipment, labor, and installation. Used for CAPEX budgeting, insurance valuation, and reserve fund analysis. Expressed in base currency (USD).',
    `room_or_zone` STRING COMMENT 'Specific room number, mechanical room designation, or building zone where the asset is installed (e.g., MER-301, Penthouse Mechanical, Zone A West Wing). Supports precise technician navigation and BIM spatial coordination.',
    `serial_number` STRING COMMENT 'Manufacturer-assigned unique serial number for the specific asset unit. Required for warranty registration, insurance claims, and regulatory compliance inspections (e.g., elevator certificates, boiler permits).',
    `source_system_code` STRING COMMENT 'Native asset identifier from the originating source system (Building Engines CMMS). Preserves the upstream system key for reconciliation, lineage tracing, and re-ingestion deduplication in the Databricks lakehouse Silver layer.',
    `useful_life_years` STRING COMMENT 'Manufacturer or engineering-estimated useful life of the asset in years from installation date. Used for depreciation schedules (FASB ASC 360), CAPEX reserve planning, and remaining useful life calculations.',
    `warranty_claim_count` STRING COMMENT 'Total number of warranty claims filed against any warranty (manufacturer, extended, or labor) for this asset since installation. Indicates reliability history and supports vendor performance evaluation.',
    CONSTRAINT pk_building_asset PRIMARY KEY(`building_asset_id`)
) COMMENT 'Master registry of all physical building equipment and infrastructure assets subject to maintenance management — HVAC units, elevators, boilers, generators, fire suppression systems, electrical panels, plumbing systems, roofing, and other O&M-tracked components. Captures asset tag, manufacturer, model, serial number, installation date, expected useful life, replacement cost, current condition rating, and BIM reference ID. Includes warranty records (manufacturer, extended, labor warranties with coverage dates and claim history) and periodic condition assessment history (condition ratings, remaining useful life estimates, recommended capital replacement year). SSOT for maintainable building equipment within the maintenance domain.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`vendor_dispatch` (
    `vendor_dispatch_id` BIGINT COMMENT 'Unique system-generated identifier for each vendor dispatch record. Primary key for the vendor_dispatch data product in the maintenance domain.',
    `asset_id` BIGINT COMMENT 'Reference to the property at which the vendor dispatch is performed. Used for CAM (Common Area Maintenance) reconciliation and property-level maintenance cost allocation.',
    `chart_of_accounts_id` BIGINT COMMENT 'Foreign key linking to finance.chart_of_accounts. Business justification: Vendor dispatches carry a gl_account_code for expense classification. A validated FK to chart_of_accounts ensures correct GL coding for AP invoice processing, CAM recoverability determination, and OpE',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Vendor dispatches generate costs allocated to cost centers for property-level expense tracking and CAM pool management. RE property accountants require cost center on vendor dispatches for AP invoice ',
    `service_contract_id` BIGINT COMMENT 'Reference to the active service contract under which this dispatch is executed. Enables SLA validation and contract compliance tracking.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Vendor work sign-off by a named employee (property manager, chief engineer) is required for invoice approval, vendor performance audits, and liability documentation in real estate operations. signoff',
    `sla_policy_id` BIGINT COMMENT 'Foreign key linking to maintenance.sla_policy. Business justification: vendor_dispatch carries denormalized sla_response_target_hours and sla_resolution_target_hours. These SLA targets are governed by sla_policy records. A FK to sla_policy normalizes the policy reference',
    `work_order_id` BIGINT COMMENT 'Reference to the parent work order that triggered this vendor dispatch. Multiple dispatches may exist per work order (e.g., return visits, multi-trade coordination).',
    `actual_arrival_timestamp` TIMESTAMP COMMENT 'Date and time the vendor technician physically arrived on-site at the property. Compared against estimated arrival window to measure SLA on-time arrival performance.',
    `actual_cost_amount` DECIMAL(18,2) COMMENT 'Actual invoiced or confirmed cost of the vendor dispatch upon completion. Compared against estimated cost for budget variance reporting and vendor cost performance analysis.',
    `actual_departure_timestamp` TIMESTAMP COMMENT 'Date and time the vendor technician departed the property after completing or suspending work. Used to calculate on-site duration and supports OSHA site safety records.',
    `building_access_required` BOOLEAN COMMENT 'Indicates whether the vendor requires escorted or key-controlled building access to perform the work. Drives property operations coordination and tenant notification requirements.',
    `capex_opex_classification` STRING COMMENT 'Accounting classification of the maintenance expenditure as Capital Expenditure (CAPEX) or Operating Expenditure (OPEX). Drives GL (General Ledger) coding, asset capitalization, and financial reporting under FASB ASC 360.. Valid values are `capex|opex|mixed|pending_review`',
    `completion_timestamp` TIMESTAMP COMMENT 'Date and time at which the vendor confirmed all work was completed and the dispatch was closed. Used for SLA resolution-time measurement and work order closure workflow.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the dispatch record was first created in the source system. Used for audit trail and data lineage tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this dispatch record (e.g., USD, EUR, GBP). Supports multi-currency portfolio reporting for international real estate portfolios.. Valid values are `^[A-Z]{3}$`',
    `dispatch_number` STRING COMMENT 'Externally-visible, human-readable dispatch reference number used in vendor communications, purchase orders, and invoice matching. Format: DSP-YYYY-NNNNNN.. Valid values are `^DSP-[0-9]{4}-[0-9]{6}$`',
    `dispatch_sequence_number` STRING COMMENT 'Sequential number of this dispatch within the parent work order (e.g., 1 for initial visit, 2 for return visit). Supports multi-trade coordination tracking and return visit analysis.',
    `dispatch_status` STRING COMMENT 'Current lifecycle state of the vendor dispatch. Tracks progression from initial dispatch through on-site work completion or cancellation. Used for SLA monitoring and vendor performance reporting.. Valid values are `dispatched|en_route|on_site|completed|cancelled|no_show`',
    `dispatch_timestamp` TIMESTAMP COMMENT 'Date and time at which the vendor or contractor was formally dispatched to the property. Serves as the principal business event timestamp for SLA response-time measurement.',
    `estimated_arrival_end` TIMESTAMP COMMENT 'End of the estimated arrival window communicated to the property manager and tenant at time of dispatch. Together with estimated_arrival_start defines the committed arrival window for SLA tracking.',
    `estimated_arrival_start` TIMESTAMP COMMENT 'Start of the estimated arrival window communicated to the property manager and tenant at time of dispatch. Used for SLA compliance measurement and tenant communication.',
    `estimated_cost_amount` DECIMAL(18,2) COMMENT 'Estimated cost of the vendor dispatch at time of scheduling, in the propertys operating currency. Used for budget variance analysis and OPEX/CAPEX forecasting.',
    `gl_account_code` STRING COMMENT 'GL (General Ledger) account code to which the dispatch cost is posted. Drives financial reporting, CAPEX/OPEX segregation, and property-level P&L allocation in Yardi Voyager.',
    `is_cam_billable` BOOLEAN COMMENT 'Indicates whether the cost of this dispatch is billable to tenants as part of CAM (Common Area Maintenance) reconciliation under NNN (Triple Net Lease) or gross lease structures.',
    `is_return_visit` BOOLEAN COMMENT 'Indicates whether this dispatch is a return visit to address incomplete or unsatisfactory work from a prior dispatch on the same work order. Used for vendor quality and rework rate analysis.',
    `parts_used_description` STRING COMMENT 'Description of parts, materials, or consumables used during the dispatch. Supports CAPEX vs. OPEX classification, warranty tracking, and invoice reconciliation.',
    `priority_level` STRING COMMENT 'Urgency classification assigned to the dispatch at the time of creation. Determines SLA response and resolution time targets and drives vendor dispatch sequencing.. Valid values are `emergency|urgent|high|normal|low`',
    `purchase_order_number` STRING COMMENT 'Purchase order number issued to the vendor for this dispatch. Enables three-way matching in AP and ensures procurement compliance for maintenance expenditures.',
    `scheduled_date` DATE COMMENT 'Calendar date on which the vendor dispatch is scheduled to occur. Used for day-level planning, preventive maintenance scheduling, and property operations calendaring.',
    `service_category` STRING COMMENT 'High-level classification of the maintenance service type. Drives CAPEX vs. OPEX accounting treatment and CAM (Common Area Maintenance) billability determination. Preventive and corrective map to OPEX; capital improvement maps to CAPEX.. Valid values are `preventive|corrective|emergency|inspection|capital_improvement|tenant_improvement`',
    `signoff_status` STRING COMMENT 'Status of the work completion sign-off by the property manager or authorized representative. Required for invoice approval and work order closure. Disputed status triggers a return visit or escalation.. Valid values are `pending|signed_off|disputed|waived`',
    `signoff_timestamp` TIMESTAMP COMMENT 'Date and time at which the authorized representative signed off on the completed dispatch work. Triggers invoice approval workflow and work order closure in Building Engines.',
    `sla_resolution_met` BOOLEAN COMMENT 'Indicates whether the vendor met the contracted SLA resolution time target (work completed within sla_resolution_target_hours of dispatch). Populated upon dispatch completion. Drives vendor performance scorecarding.',
    `sla_resolution_target_hours` DECIMAL(18,2) COMMENT 'Contracted SLA (Service Level Agreement) target for total resolution time in hours from dispatch to work completion, as defined in the service contract. Supports vendor performance scorecarding.',
    `sla_response_met` BOOLEAN COMMENT 'Indicates whether the vendor met the contracted SLA response time target (arrival within sla_response_target_hours of dispatch). Populated upon actual arrival. Drives vendor performance KPI reporting.',
    `sla_response_target_hours` DECIMAL(18,2) COMMENT 'Contracted SLA (Service Level Agreement) target for vendor response time in hours from dispatch to on-site arrival, as defined in the service contract. Used for SLA compliance measurement.',
    `source_system_code` STRING COMMENT 'Native record identifier from the originating source system (Building Engines CMMS). Enables traceability and reconciliation between the lakehouse silver layer and the operational system of record.',
    `tenant_notification_required` BOOLEAN COMMENT 'Indicates whether the tenant must be notified prior to the vendor accessing the leased premises. Driven by lease terms, building rules, and tenant service request origin.',
    `trade_type` STRING COMMENT 'Classification of the trade or technical discipline of the dispatched vendor (e.g., HVAC, plumbing, electrical, elevator, janitorial, roofing, fire safety). Used for multi-trade coordination and CAPEX vs. OPEX classification. [ENUM-REF-CANDIDATE: hvac|plumbing|electrical|elevator|fire_safety|roofing|janitorial|structural|landscaping|pest_control — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when the dispatch record was last modified in the source system. Supports change tracking and incremental data pipeline processing.',
    `vendor_contact_name` STRING COMMENT 'Full name of the individual technician or field representative dispatched on behalf of the vendor. Used for on-site sign-off and OSHA safety compliance records.',
    `vendor_contact_phone` STRING COMMENT 'Mobile or direct phone number of the dispatched technician or vendor representative for on-site coordination and emergency contact.. Valid values are `^+?[0-9s-().]{7,20}$`',
    `vendor_name` STRING COMMENT 'Legal or trade name of the vendor or contractor dispatched. Captured at dispatch time for historical accuracy independent of vendor master updates.',
    `work_performed_summary` STRING COMMENT 'Free-text narrative description of the work performed by the vendor during this dispatch. Captured by the technician or property manager at completion. Supports maintenance history, asset condition tracking, and audit documentation.',
    CONSTRAINT pk_vendor_dispatch PRIMARY KEY(`vendor_dispatch_id`)
) COMMENT 'Transactional record of a vendor or contractor dispatched to a property to fulfill a work order. Captures the dispatched vendor, dispatch timestamp, estimated arrival window, actual arrival and departure times, work performed summary, sign-off status, and invoice reference. Tracks vendor performance against SLA commitments and supports CAM reconciliation for billable maintenance costs. Multiple dispatches may occur per work order (e.g., return visits, multi-trade coordination).';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`service_contract` (
    `service_contract_id` BIGINT COMMENT 'Unique system-generated identifier for the maintenance service contract record. Primary key for the service_contract data product in the maintenance domain.',
    `asset_id` BIGINT COMMENT 'Reference to the primary property covered by this service contract. For multi-property contracts, this represents the lead or billing property; additional covered properties are tracked in a separate association table.',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Service contracts (elevator maintenance, HVAC service, janitorial) are scoped to specific buildings. Building-level contract management, cost reporting, and vendor performance tracking are standard pr',
    `chart_of_accounts_id` BIGINT COMMENT 'Foreign key linking to finance.chart_of_accounts. Business justification: Service contracts carry a gl_account_code for expense classification and CAM recoverability determination. A validated FK to chart_of_accounts supports AP invoice coding, CAM reconciliation, and FASB ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Service contracts represent committed annual costs allocated to cost centers for property-level expense budgeting and CAM pool management. RE controllers require cost center assignment on service cont',
    `finance_budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: Service contracts are approved against annual maintenance budgets. RE asset managers track contracted spend vs. budget for each property. This link supports budget commitment tracking, annual budget p',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Service contracts for regulated equipment (elevators, boilers, fire suppression) are required by regulatory obligations. Compliance officers verifying that mandatory service agreements are in place li',
    `vendor_id` BIGINT COMMENT 'Reference to the vendor or service provider party responsible for delivering services under this contract (e.g., HVAC contractor, janitorial company, elevator service firm).',
    `annual_contract_value` DECIMAL(18,2) COMMENT 'Total annualized monetary value of the service contract in the operating currency. Used for OPEX/CAPEX budgeting, vendor spend analytics, and portfolio-level O&M cost reporting. Expressed in the propertys functional currency.',
    `auto_renewal_flag` BOOLEAN COMMENT 'Indicates whether this contract automatically renews at expiration unless notice of termination is provided within the required notice period. Critical for contract management and avoiding unintended renewals.',
    `building_engines_contract_code` STRING COMMENT 'Source system identifier for this contract record in Building Engines CMMS. Used for data lineage, ETL reconciliation, and bi-directional sync between the lakehouse silver layer and the operational system.',
    `capex_opex_classification` STRING COMMENT 'Accounting classification of the contract spend as Capital Expenditure (CAPEX), Operating Expenditure (OPEX), or Mixed. Drives GL account coding in Yardi and SAP S/4HANA. Critical for NOI calculation, asset capitalization, and REIT financial reporting under FASB and IFRS.. Valid values are `capex|opex|mixed`',
    `commencement_date` DATE COMMENT 'The date on which the service contract becomes effective and the vendor is authorized to begin providing services. Aligns with FASB ASC 842 and IFRS 16 contract start date concepts for service agreement accounting.',
    `contract_document_url` STRING COMMENT 'Secure URL or document management system path to the fully executed contract document. Provides direct access to the contract for legal review, audit, and compliance purposes.',
    `contract_name` STRING COMMENT 'Descriptive name of the service contract (e.g., Annual HVAC Maintenance Agreement — Tower A, Janitorial Services Contract — Portfolio Wide). Used for display and search in Building Engines and Yardi.',
    `contract_notes` STRING COMMENT 'Free-text field for operational notes, special conditions, exceptions, or amendments not captured in structured fields. Used by property managers and asset managers for contract administration context.',
    `contract_number` STRING COMMENT 'Externally-known, human-readable contract reference number assigned at execution. Used for vendor correspondence, purchase orders, and audit trails. Sourced from DocuSign CLM or Building Engines contract module.. Valid values are `^SC-[A-Z0-9]{4,20}$`',
    `contract_status` STRING COMMENT 'Current lifecycle state of the service contract. Drives operational workflows: active contracts authorize vendor dispatch; expired/terminated contracts block new work orders against this contract.. Valid values are `draft|active|expired|terminated|pending_renewal|suspended`',
    `contract_type` STRING COMMENT 'Classification of the service contract by the type of facility service covered. Drives routing to the appropriate operations team and CAPEX/OPEX classification rules. [ENUM-REF-CANDIDATE: hvac|elevator|janitorial|landscaping|pest_control|security|fire_life_safety|plumbing|electrical|roofing|general_maintenance|other — promote to reference product]',
    `covered_equipment_description` STRING COMMENT 'Description of specific building equipment, systems, or assets covered under this contract (e.g., All rooftop HVAC units — Building A and B, Passenger elevators 1-4). Supports asset lifecycle tracking and BIM integration.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this service contract record was first created in the system. Supports audit trail, data lineage, and SOX financial controls compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary values on this contract (e.g., USD, CAD, GBP). Supports multi-currency portfolio reporting for international real estate portfolios.. Valid values are `^[A-Z]{3}$`',
    `docusign_envelope_code` STRING COMMENT 'Unique envelope identifier from DocuSign CLM for the executed contract document. Enables direct retrieval of the signed contract document and audit trail of digital signatures.',
    `esg_sustainability_flag` BOOLEAN COMMENT 'Indicates whether this contract includes ESG or green building sustainability requirements (e.g., use of eco-friendly cleaning products, LEED-compliant HVAC maintenance practices, EPA-compliant pest control methods).',
    `execution_date` DATE COMMENT 'The date on which all parties signed and the contract was fully executed. May differ from commencement date. Sourced from DocuSign CLM digital signature completion timestamp.',
    `expiration_date` DATE COMMENT 'The date on which the service contract term ends and the vendors obligation to provide services ceases, absent renewal. Nullable for evergreen/open-ended contracts. Critical for renewal management and WALE (Weighted Average Lease Expiry) analogous tracking.',
    `gl_account_code` STRING COMMENT 'General Ledger account code to which contract costs are posted in the financial system (Yardi Voyager or SAP S/4HANA). Ensures correct cost allocation for NOI reporting, budget variance analysis, and REIT financial statements.',
    `insurance_expiration_date` DATE COMMENT 'Expiration date of the vendors current certificate of insurance (COI) on file. Triggers compliance alerts when insurance is approaching expiration to prevent lapsed coverage during active contract period.',
    `insurance_liability_limit` DECIMAL(18,2) COMMENT 'Minimum required general liability insurance coverage amount (in contract currency) that the vendor must maintain throughout the contract term. Used for risk management and compliance verification.',
    `insurance_required_flag` BOOLEAN COMMENT 'Indicates whether the vendor is contractually required to provide a certificate of insurance (COI) as a condition of performing services. Supports OSHA compliance and risk management workflows.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this service contract record. Used for change data capture (CDC) in the Databricks lakehouse silver layer pipeline and SOX audit trail.',
    `lien_waiver_required_flag` BOOLEAN COMMENT 'Indicates whether the vendor must provide a lien waiver upon payment as a condition of this contract. Relevant for CAPEX-classified contracts and construction-adjacent maintenance work to protect property title.',
    `multi_property_flag` BOOLEAN COMMENT 'Indicates whether this service contract covers multiple properties in the portfolio (e.g., a portfolio-wide janitorial contract). When true, additional covered properties are tracked in a separate association table.',
    `osha_compliance_required_flag` BOOLEAN COMMENT 'Indicates whether the vendor must comply with specific OSHA safety standards as a condition of this contract (e.g., confined space entry, lockout/tagout, fall protection). Drives safety documentation requirements in Building Engines.',
    `payment_frequency` STRING COMMENT 'Frequency at which the vendor invoices and payment is due under the contract terms. Drives AP (Accounts Payable) accrual schedules in Yardi Voyager and SAP S/4HANA.. Valid values are `monthly|quarterly|semi_annual|annual|per_visit|milestone`',
    `performance_bond_required_flag` BOOLEAN COMMENT 'Indicates whether the vendor is required to provide a performance bond guaranteeing contract completion. Typically required for high-value CAPEX contracts or critical building systems.',
    `preventive_maintenance_frequency` STRING COMMENT 'Scheduled frequency of preventive maintenance visits or inspections required under this contract. Drives PM schedule generation in Building Engines CMMS and supports OSHA and equipment warranty compliance.. Valid values are `weekly|monthly|quarterly|semi_annual|annual|as_needed`',
    `renewal_term_months` STRING COMMENT 'Duration in months of each automatic or optional renewal period. Used to calculate the extended contract end date upon renewal and for WALT (Weighted Average Lease Term) analogous vendor contract duration analytics.',
    `service_scope_description` STRING COMMENT 'Detailed narrative description of the services covered under this contract, including specific equipment, systems, buildings, or areas included. Defines the scope of work (SOW) for vendor dispatch and work order validation in Building Engines.',
    `sla_resolution_time_hours` DECIMAL(18,2) COMMENT 'Contractually committed maximum time in hours from service request submission to full resolution and sign-off. Distinct from response time — measures end-to-end resolution commitment for SLA compliance reporting.',
    `sla_response_time_hours` DECIMAL(18,2) COMMENT 'Contractually committed maximum response time in hours from service request submission to vendor on-site arrival for emergency or priority calls. Key SLA metric tracked in Building Engines for vendor performance management.',
    `termination_date` DATE COMMENT 'Actual date on which the contract was terminated early, if applicable. Null for contracts that run to natural expiration. Distinct from expiration_date — captures unscheduled early termination events.',
    `termination_notice_days` STRING COMMENT 'Number of calendar days of advance written notice required by either party to terminate the contract or prevent auto-renewal. Drives contract expiry alerts and renewal decision workflows.',
    `termination_reason` STRING COMMENT 'Reason code for early contract termination. Used for vendor performance analytics, procurement strategy, and regulatory compliance reporting.. Valid values are `vendor_default|mutual_agreement|property_disposition|budget_reduction|scope_change|other`',
    `total_contract_value` DECIMAL(18,2) COMMENT 'Total monetary value of the service contract over its full term, including all renewal options if exercised. Used for capital planning, vendor spend management, and CAPEX vs. OPEX threshold analysis.',
    `vendor_contact_name` STRING COMMENT 'Name of the primary vendor contact person responsible for this contract — typically the account manager or service coordinator. Used for operational communication and escalation.',
    `vendor_contact_phone` STRING COMMENT 'Direct phone number for the vendors primary contract contact. Used for emergency dispatch and SLA escalation. Classified as confidential PII per GDPR Article 4.. Valid values are `^+?[0-9s-().]{7,20}$`',
    `vendor_contract_reference` STRING COMMENT 'The vendors own internal contract or purchase order reference number for this agreement. Enables cross-referencing between the property managers system and the vendors billing system.',
    CONSTRAINT pk_service_contract PRIMARY KEY(`service_contract_id`)
) COMMENT 'Master record for a maintenance service contract or vendor agreement governing recurring facility services — HVAC maintenance contracts, elevator service agreements, janitorial contracts, landscaping, pest control, and security. Captures contract number, vendor, covered properties, service scope, contract start/end dates, renewal terms, annual contract value, SLA terms, insurance certificate requirements, and CAPEX vs. OPEX classification. Distinct from individual work orders — this is the standing contractual framework.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`ops_inspection` (
    `ops_inspection_id` BIGINT COMMENT 'Unique surrogate identifier for each formal property or equipment inspection event record in the maintenance domain. Primary key for the ops_inspection data product.',
    `amenity_id` BIGINT COMMENT 'Foreign key linking to property.amenity. Business justification: Amenity inspections (pool safety certification, gym equipment inspection, playground safety) are a distinct inspection category required for liability management and regulatory compliance.',
    `brokerage_deal_id` BIGINT COMMENT 'Foreign key linking to brokerage.deal. Business justification: Due diligence property inspections are a named phase of commercial real estate transactions. Inspection findings directly affect deal pricing, closing conditions, and remediation obligations. Domain e',
    `building_asset_id` BIGINT COMMENT 'Foreign key linking to maintenance.building_asset. Business justification: Formal property inspections (fire safety, elevator certification, HVAC compliance) are performed on specific physical building assets tracked in building_asset. While ops_inspection already links to p',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Operational inspections (fire safety, elevator, boiler) are conducted at the building level. Building-level compliance certificate tracking and regulatory reporting (fire marshal, building department)',
    `common_area_id` BIGINT COMMENT 'Foreign key linking to property.common_area. Business justification: Common area inspections (fire egress, ADA compliance, elevator lobbies) are a distinct inspection category. Linking to common_area supports compliance reporting and CAM cost allocation for remediation',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Operational inspections (elevator, boiler, fire suppression) validate or are required by specific operating permits. A property compliance officer links inspection outcomes to the permit being validat',
    `violation_id` BIGINT COMMENT 'Foreign key linking to compliance.violation. Business justification: Operational inspections with critical deficiencies result in compliance violation citations from regulators. A compliance officer tracking violation abatement needs to link the inspection that trigger',
    `construction_permit_id` BIGINT COMMENT 'Foreign key linking to development.construction_permit. Business justification: Post-renovation operational inspections (COO compliance, fire safety sign-off) are required by permit conditions. Linking ops_inspection to construction_permit enables permit closeout tracking and reg',
    `contractor_id` BIGINT COMMENT 'Reference to the third-party inspection firm or licensed inspector vendor who conducted the inspection. Null when the inspection is performed by internal staff.',
    `dev_project_id` BIGINT COMMENT 'Foreign key linking to development.dev_project. Business justification: COO-related and post-construction operational inspections (ops_inspection.coo_compliance_flag) must be traceable to the development project for regulatory closeout. Real estate developers require this',
    `environmental_review_id` BIGINT COMMENT 'Foreign key linking to development.environmental_review. Business justification: Operational inspections for properties with known environmental conditions (Phase I/II findings, remediation sites) must reference the environmental review to ensure ongoing monitoring compliance. Rea',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Internal inspection review sign-off by a specific employee is required for regulatory compliance tracking, COO issuance, and LEED/BREEAM certification workflows. internal_reviewer_name is a denormal',
    `listing_id` BIGINT COMMENT 'Foreign key linking to brokerage.listing. Business justification: Pre-listing property condition inspections are conducted before a property is listed for sale or lease. Inspection results are disclosed to prospects and affect listing terms and marketing. Domain exp',
    `parking_id` BIGINT COMMENT 'Foreign key linking to property.parking. Business justification: Parking structure inspections (structural integrity, fire safety, ADA compliance) are a distinct inspection category. Compliance certificate tracking for parking facilities requires linking inspection',
    `asset_id` BIGINT COMMENT 'Reference to the property at which the inspection was conducted. Links to the property master record in the property domain.',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Commercial space inspections (pre-lease condition, TI completion sign-off, post-lease restoration) are conducted at the space level. Space-level inspection records support lease administration and TI ',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Operational inspections (fire suppression, elevator, HVAC) are mandated by specific regulatory obligations. Compliance officers need to link each inspection to the governing obligation to track fulfil',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to insurance.risk_assessment. Business justification: Insurance underwriters require operational inspection records (fire safety, elevator, structural) as inputs to property risk assessments at renewal. Real estate risk managers submit inspection finding',
    `service_contract_id` BIGINT COMMENT 'Foreign key linking to maintenance.service_contract. Business justification: Many formal inspections (elevator certifications, fire suppression checks, HVAC compliance) are performed under the terms of a service contract. Linking ops_inspection to service_contract enables trac',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Unit-level inspections (move-in/move-out, habitability, smoke detector compliance) are standard in residential property management. Housing code regulations require unit-level inspection records.',
    `actual_remediation_cost` DECIMAL(18,2) COMMENT 'Actual total cost incurred to remediate all deficiencies identified in this inspection, recorded upon completion of corrective work orders. Compared against estimated_remediation_cost for budget variance analysis.',
    `building_area` STRING COMMENT 'Specific floor, zone, wing, or common area of the building where the inspection was performed (e.g., Floor 3 East Wing, Basement Mechanical Room, Rooftop). Supports spatial analysis of deficiency patterns.',
    `capex_opex_classification` STRING COMMENT 'Classification of the remediation costs associated with deficiencies found in this inspection as Capital Expenditure (CAPEX) or Operating Expenditure (OPEX), or a mix of both. Critical for financial reporting under FASB ASC 360 and internal budgeting.. Valid values are `capex|opex|mixed`',
    `certificate_expiry_date` DATE COMMENT 'Expiration date of the compliance certificate or permit issued as a result of a passed inspection (e.g., elevator operating certificate, fire safety certificate). Null if no certificate is issued.',
    `coo_compliance_flag` BOOLEAN COMMENT 'Indicates whether this inspection is required to maintain or renew the Certificate of Occupancy (COO) for the property. True when the inspection is a COO-mandated compliance event.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this inspection record was first created in the source system (Building Engines). Audit trail field for data lineage and compliance purposes.',
    `critical_deficiency_count` STRING COMMENT 'Number of deficiency findings classified as critical severity — those posing immediate life-safety risk or requiring emergency corrective action. Drives escalation workflows and OSHA reporting obligations.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to all monetary amounts on this inspection record (e.g., USD, GBP, EUR). Supports multi-currency portfolio reporting.. Valid values are `^[A-Z]{3}$`',
    `deficiency_count` STRING COMMENT 'Total number of individual deficiency findings identified during the inspection across all severity levels. Provides a summary count for compliance dashboards and trend analysis.',
    `esg_relevant_flag` BOOLEAN COMMENT 'Indicates whether this inspection has ESG reporting relevance (e.g., LEED commissioning, BREEAM assessment, EPA environmental compliance inspection). Supports ESG portfolio reporting for REITs and institutional investors.',
    `estimated_remediation_cost` DECIMAL(18,2) COMMENT 'Estimated total cost in the base currency to remediate all deficiencies identified in this inspection. Used for CAPEX/OPEX budgeting and asset lifecycle planning.',
    `inspecting_party_type` STRING COMMENT 'Indicates whether the inspection was conducted by internal facility staff, an external third-party inspection firm, or a government/regulatory authority (e.g., fire marshal, building department).. Valid values are `internal|third_party|regulatory_authority`',
    `inspection_date` DATE COMMENT 'The actual calendar date on which the inspection was conducted. This is the principal real-world business event date for the inspection record.',
    `inspection_end_time` TIMESTAMP COMMENT 'Precise date and time when the inspection was concluded on-site. Combined with inspection_start_time to derive inspection duration for O&M analytics.',
    `inspection_firm_name` STRING COMMENT 'Name of the third-party inspection company or regulatory agency that conducted the inspection. Null for internal inspections.',
    `inspection_notes` STRING COMMENT 'Free-text narrative notes recorded by the inspector or internal reviewer providing additional context, observations, or recommendations not captured in structured fields. Sourced from Building Engines work order comments.',
    `inspection_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to the inspection event, sourced from Building Engines or the inspecting authority. Used for cross-referencing with regulatory filings, certificates, and work orders.',
    `inspection_report_ref` STRING COMMENT 'Document reference number or URL path to the formal inspection report issued by the inspecting party. Supports document management integration with DocuSign CLM or Building Engines document store.',
    `inspection_result` STRING COMMENT 'Overall pass/fail outcome of the inspection as determined by the inspecting party. Conditional pass indicates the property passed subject to minor corrective actions within a defined timeframe.. Valid values are `pass|fail|conditional_pass|incomplete|not_applicable`',
    `inspection_scope` STRING COMMENT 'Narrative description of the areas, systems, or equipment covered by the inspection (e.g., All fire suppression systems on floors 1-10, Rooftop HVAC units RTU-01 through RTU-06). Sourced from Building Engines work order scope.',
    `inspection_start_time` TIMESTAMP COMMENT 'Precise date and time when the inspection commenced on-site. Used for duration tracking and scheduling conflict analysis.',
    `inspection_status` STRING COMMENT 'Current lifecycle state of the inspection event workflow within Building Engines. Tracks progression from scheduling through completion or cancellation.. Valid values are `scheduled|in_progress|completed|cancelled|deferred`',
    `inspection_subtype` STRING COMMENT 'Further granular classification within the inspection type (e.g., Annual Fire Sprinkler Test, Five-Year Elevator Full Load Test, Pre-Occupancy HVAC Commissioning). Supports detailed regulatory citation mapping.',
    `inspection_type` STRING COMMENT 'Classification of the inspection category. Covers fire safety inspections, elevator certifications, HVAC commissioning, roof inspections, ADA/accessibility compliance walkthroughs, and workplace safety audits. [ENUM-REF-CANDIDATE: fire_safety|elevator_certification|hvac_commissioning|roof|ada_accessibility|workplace_safety|environmental|plumbing|electrical|general_property — promote to reference product]',
    `inspector_license_number` STRING COMMENT 'Professional license or certification number of the inspector as issued by the relevant regulatory or licensing authority (e.g., state elevator inspector license, fire protection engineer PE number).',
    `inspector_name` STRING COMMENT 'Full name of the individual inspector or lead inspector who conducted the inspection. May be an internal employee or a licensed third-party inspector.',
    `leed_breeam_reference` STRING COMMENT 'Reference code or credit identifier linking this inspection to a specific LEED or BREEAM certification credit or prerequisite (e.g., LEED EA Prerequisite 1 — Fundamental Commissioning). Null when not ESG-relevant.',
    `major_deficiency_count` STRING COMMENT 'Number of deficiency findings classified as major severity — significant non-conformances requiring corrective action within a defined regulatory or contractual timeframe.',
    `minor_deficiency_count` STRING COMMENT 'Number of deficiency findings classified as minor severity — low-risk observations that should be addressed in routine maintenance cycles but do not pose immediate safety or compliance risk.',
    `next_inspection_due_date` DATE COMMENT 'The date by which the next recurring inspection of this type must be completed to maintain regulatory compliance and Certificate of Occupancy (COO) obligations.',
    `open_deficiency_count` STRING COMMENT 'Number of deficiency findings from this inspection that remain unresolved (not yet remediated or closed). Key metric for tracking open compliance obligations and COO maintenance.',
    `osha_reportable_flag` BOOLEAN COMMENT 'Indicates whether any findings from this inspection trigger mandatory OSHA reporting obligations (e.g., imminent danger, serious violations under 29 CFR 1910). Drives compliance escalation workflows.',
    `review_date` DATE COMMENT 'Date on which the internal reviewer acknowledged and accepted the inspection report and findings. Marks the start of the internal remediation planning cycle.',
    `scheduled_date` DATE COMMENT 'The planned calendar date on which the inspection was originally scheduled to occur. Used for maintenance planning and regulatory compliance scheduling.',
    `source_system_code` STRING COMMENT 'The native record identifier from the originating Building Engines CMMS system for this inspection event. Supports data lineage, reconciliation, and incremental load processing in the Databricks Silver layer.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this inspection record was most recently modified in the source system (Building Engines). Used for incremental data pipeline processing and audit trail maintenance in the Databricks Silver layer.',
    CONSTRAINT pk_ops_inspection PRIMARY KEY(`ops_inspection_id`)
) COMMENT 'Record of a formal property or equipment inspection event — fire safety inspections, elevator certifications, HVAC commissioning, roof inspections, ADA/accessibility compliance walkthroughs, and workplace safety audits (OSHA, HSE, or equivalent). Captures inspection type, inspecting party (internal or third-party), inspection date, pass/fail result, and regulatory citation reference. Includes individual deficiency findings with severity classification (critical, major, minor), affected asset or area, recommended corrective action, responsible party, target and actual remediation dates, and remediation work order references. Supports regulatory compliance, certificate of occupancy maintenance obligations, and tracking of open deficiencies through to resolution.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`capex_project` (
    `capex_project_id` BIGINT COMMENT 'Primary key for capex_project',
    `amenity_id` BIGINT COMMENT 'Foreign key linking to property.amenity. Business justification: Amenity upgrade capex (pool renovation, gym equipment replacement, rooftop terrace build-out) is tracked at the amenity level. Amenity-level capex supports asset value, NOI, and competitive positionin',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Capital expenditure approval by an authorized employee (VP Asset Management, CFO) is a core real estate governance requirement for capital budget control, audit trails, and board reporting. approver_',
    `brokerage_deal_id` BIGINT COMMENT 'Foreign key linking to brokerage.deal. Business justification: Tenant Improvement capex projects are directly triggered by lease deals specifying TI allowances. Asset managers track capex spend against deal-committed TI budgets. A real estate domain expert expect',
    `building_asset_id` BIGINT COMMENT 'Reference to the specific building asset or equipment unit being improved or replaced. Links to the fixed asset register in Yardi Voyager or SAP FA module for capitalization and depreciation scheduling.',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Capex projects (roof replacement, lobby renovation, elevator modernization) are scoped to a specific building. Building-level capex budget vs. actual reporting is a core real estate asset management r',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Real estate asset repositioning process: capex projects (lobby renovations, amenity upgrades) are paired with marketing campaigns to drive leasing velocity. Renovation marketing ROI reporting requir',
    `chart_of_accounts_id` BIGINT COMMENT 'Foreign key linking to finance.chart_of_accounts. Business justification: CapEx projects carry a gl_account_code for capitalization entries and asset class coding. A validated FK to chart_of_accounts ensures correct asset account assignment for fixed asset creation, depreci',
    `common_area_id` BIGINT COMMENT 'Foreign key linking to property.common_area. Business justification: Common area renovation capex (lobby renovation, corridor upgrade, restroom modernization) is a major real estate capex category. Common area-level capex tracking supports CAM cost basis and asset valu',
    `assessment_id` BIGINT COMMENT 'Foreign key linking to compliance.assessment. Business justification: Capex projects are triggered by compliance assessments (Phase II environmental assessments triggering remediation capex, property condition assessments driving capital planning). Compliance officers t',
    `green_certification_id` BIGINT COMMENT 'Foreign key linking to compliance.green_certification. Business justification: Capex projects (energy retrofits, building envelope upgrades, lighting replacements) are undertaken to achieve or maintain LEED/BREEAM certifications. Sustainability managers track which capital proje',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Capex projects (roof replacement, HVAC overhaul, tenant improvements) require building permits. Project managers track permit status against project milestones. permit_number and permit_issued_date on',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: CapEx projects are tracked by cost center for capital budget allocation, fixed asset capitalization, and depreciation assignment. RE finance teams require cost center on capex projects for capital exp',
    `design_document_id` BIGINT COMMENT 'Foreign key linking to development.design_document. Business justification: Maintenance CAPEX renovation projects are executed against architectural and engineering design documents (drawings, specifications). Linking capex_project to design_document enables scope verificatio',
    `dev_project_id` BIGINT COMMENT 'Foreign key linking to development.dev_project. Business justification: Capital renewal projects (roof, HVAC overhaul) are often spawned from or coordinated with a development project during phased renovation or handover. Asset managers track maintenance CAPEX against the',
    `entitlement_id` BIGINT COMMENT 'Foreign key linking to development.entitlement. Business justification: Significant maintenance CAPEX projects (major additions, change-of-use renovations) require zoning entitlements. Linking capex_project to entitlement enables regulatory compliance tracking and ensures',
    `finance_budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: CapEx projects are approved against capital budgets. RE asset managers track approved_budget_amount vs. actual_spend_to_date against the budget record for capital planning, board reporting, and lender',
    `owner_agreement_id` BIGINT COMMENT 'Foreign key linking to owner.owner_agreement. Business justification: Capital expenditure approval workflow: capex projects on an owners asset must be authorized under the governing owner agreement (capex_approval_threshold). Property managers and auditors require this',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to property.parcel. Business justification: Land development capex (grading, utilities, infrastructure installation on vacant land) is scoped to a specific parcel. Parcel-level capex tracking is required for land development cost basis and enti',
    `parking_id` BIGINT COMMENT 'Foreign key linking to property.parking. Business justification: Parking facility capex (resurfacing, gate replacement, EV charger installation) is tracked at the parking facility level. Parking-level capex supports parking asset value, replacement planning, and EV',
    `asset_id` BIGINT COMMENT 'Reference to the property where the capital project is being executed. Links the CAPEX project to the property master record for portfolio-level CAPEX reporting, NOI impact analysis, and asset register updates.',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Commercial TI projects are scoped to specific leasable spaces. Space-level capex tracking supports TI allowance reconciliation against lease agreements and space cost basis reporting.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Capex projects mandated by regulatory obligations (ADA compliance upgrades, fire code remediation, environmental remediation orders) must be traceable to the governing obligation. Compliance officers ',
    `service_contract_id` BIGINT COMMENT 'Foreign key linking to maintenance.service_contract. Business justification: CAPEX projects are frequently executed under a service contract with a primary contractor. capex_project carries primary_contractor_name (STRING) and contract_value_amount (DECIMAL) as denormalized fi',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Tenant improvement (TI) capex projects are scoped to specific units. TI allowance tracking, lease-related capex reporting, and unit cost basis calculations require unit-level capex linkage.',
    `actual_completion_date` DATE COMMENT 'Date on which the capital project reached substantial completion and was accepted. Triggers the capitalization process and fixed asset creation in the GL. Compared against planned completion for schedule variance reporting.',
    `actual_spend_to_date` DECIMAL(18,2) COMMENT 'Cumulative actual expenditure incurred on the project to date, sourced from SAP S/4HANA cost collection or Yardi AP postings. Used for budget variance analysis, cash flow forecasting, and CAPEX vs. OPEX classification reporting.',
    `actual_start_date` DATE COMMENT 'Date on which project construction or installation activities actually commenced. Compared against planned start date for schedule variance analysis and contractor performance evaluation.',
    `approval_authority` STRING COMMENT 'Level of organizational authority that approved this capital project. Reflects the delegation of authority matrix for CAPEX approvals. Used for SOX controls documentation and audit trail. [ENUM-REF-CANDIDATE: property_manager|asset_manager|vp_operations|cfo|investment_committee|board — promote to reference product]. Valid values are `property_manager|asset_manager|vp_operations|cfo|investment_committee|board`',
    `approval_date` DATE COMMENT 'Date on which the capital project received formal investment committee or board approval. Required for SOX financial controls documentation and CAPEX authorization audit trail.',
    `approved_budget_amount` DECIMAL(18,2) COMMENT 'Board or investment committee approved budget for the capital project in the operating currency. Represents the authorized CAPEX spend ceiling. Used for variance analysis against actual spend and DSCR/LTV covenant compliance reporting.',
    `asset_category` STRING COMMENT 'Classification of the asset being created or improved by the capital project. Determines the depreciation method and useful life schedule applied upon capitalization. Aligns with the fixed asset register taxonomy in Yardi and SAP. [ENUM-REF-CANDIDATE: building_structure|mechanical_systems|electrical_systems|plumbing_systems|hvac|roof|elevators|parking|it_infrastructure|fit_out — promote to reference product]',
    `capitalization_date` DATE COMMENT 'Date on which the completed project costs were capitalized and transferred to the fixed asset register in the GL. Marks the start of the depreciation schedule. Critical for FASB ASC 360 compliance and balance sheet accuracy.',
    `change_order_amount` DECIMAL(18,2) COMMENT 'Cumulative value of all approved change orders against the primary construction contract. Added to the original contract value to determine the revised contract sum. Used for budget variance analysis.',
    `change_order_count` STRING COMMENT 'Total number of approved change orders issued against the primary construction contract. Indicates project scope stability and contractor performance. High change order counts may signal design deficiency or scope creep.',
    `committed_cost_amount` DECIMAL(18,2) COMMENT 'Total value of purchase orders and contracts committed but not yet invoiced or paid for this project. Represents financial obligations already incurred. Used in cash flow forecasting and budget-to-complete analysis.',
    `contract_value_amount` DECIMAL(18,2) COMMENT 'Total contracted value with the primary general contractor for execution of the capital project. May differ from approved budget due to contingency reserves or owner-direct procurement. Used for commitment tracking and lien exposure management.',
    `coo_issued_date` DATE COMMENT 'Date on which the Certificate of Occupancy (COO) was issued by the relevant authority, confirming the completed improvement meets all building code and safety requirements. Required before tenant occupancy and asset capitalization.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the capital project record was first created in the system. Supports audit trail, data lineage, and SOX financial controls documentation. Sourced from Building Engines or Procore at project initiation.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this project record (e.g., USD, EUR, GBP). Supports multi-currency portfolio reporting for international real estate portfolios and REIT financial consolidation.. Valid values are `^[A-Z]{3}$`',
    `depreciation_method` STRING COMMENT 'Accounting depreciation method to be applied to the capitalized asset upon project completion. Determined by asset category and accounting policy. Straight-line is most common for real estate assets under FASB ASC 360.. Valid values are `straight_line|declining_balance|units_of_production|sum_of_years_digits`',
    `erp_project_code` STRING COMMENT 'Project code assigned in SAP S/4HANA Project Systems (PS module) for cost collection, procurement integration, and financial consolidation. Used to reconcile CAPEX spend between the maintenance CMMS and the ERP general ledger.',
    `funding_source` STRING COMMENT 'Source of funds financing the capital project. Determines accounting treatment, loan covenant implications, and investor reporting requirements. Insurance proceeds and tenant reimbursements have distinct revenue recognition rules. [ENUM-REF-CANDIDATE: operating_reserves|debt_financing|equity_contribution|insurance_proceeds|tenant_reimbursement|government_grant|refinancing_proceeds — promote to reference product]',
    `gl_account_code` STRING COMMENT 'General Ledger account code in Yardi Voyager or SAP S/4HANA to which CAPEX project costs are posted. Ensures correct balance sheet classification (asset vs. expense) and supports financial consolidation and audit.',
    `is_esg_initiative` BOOLEAN COMMENT 'Indicates whether this capital project is classified as an ESG initiative (e.g., LEED certification upgrade, BREEAM improvement, energy efficiency retrofit, EV charging installation). Supports ESG portfolio reporting and green financing eligibility.',
    `is_tenant_improvement` BOOLEAN COMMENT 'Indicates whether this capital project constitutes a Tenant Improvement (TI) as defined under ASC 842 or IFRS 16. TI projects have distinct lease accounting treatment, amortization rules, and may be partially reimbursed by tenants.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the capital project record. Used for incremental data pipeline processing, change detection, and audit trail maintenance in the Databricks Silver Layer.',
    `leed_certification_target` STRING COMMENT 'Target LEED certification level sought for this capital project, if applicable. Relevant for green building upgrades and ESG-linked financing. Null or none if LEED certification is not a project objective.. Valid values are `certified|silver|gold|platinum|none`',
    `osha_compliance_required` BOOLEAN COMMENT 'Indicates whether this capital project has mandatory OSHA safety compliance requirements (e.g., asbestos abatement, fall protection systems, electrical safety upgrades). Triggers safety inspection and documentation workflows.',
    `planned_completion_date` DATE COMMENT 'Originally scheduled date for substantial completion of the capital project. Used for tenant coordination, COO applications, and fixed asset capitalization planning.',
    `planned_start_date` DATE COMMENT 'Originally scheduled start date for project construction or installation activities. Used for project scheduling, contractor mobilization planning, and tenant disruption coordination.',
    `primary_contractor_name` STRING COMMENT 'Name of the primary general contractor or construction firm engaged to execute the capital project. Used for vendor performance tracking, insurance certificate management, and lien waiver documentation.',
    `priority_level` STRING COMMENT 'Business priority classification of the capital project, reflecting urgency, safety risk, regulatory compliance obligation, or strategic importance. Critical projects may involve OSHA safety compliance or COO requirements.. Valid values are `critical|high|medium|low`',
    `procore_project_code` STRING COMMENT 'External project identifier from Procore construction management system. Enables cross-system traceability for RFIs, submittals, change orders, and document control records associated with this CAPEX project.',
    `project_description` STRING COMMENT 'Detailed narrative describing the scope of work, business justification, and expected outcome of the capital project. Supports investment committee review, LOI documentation, and regulatory compliance reporting.',
    `project_name` STRING COMMENT 'Descriptive short name for the capital project (e.g., HVAC Chiller Replacement — Tower A, Roof Membrane Renewal — Building 3). Used in reporting dashboards, budget approvals, and fixed asset registers.',
    `project_number` STRING COMMENT 'Externally-known, human-readable project identifier assigned at project initiation. Used across Procore, SAP S/4HANA Project Systems, and Yardi Fixed Assets for cross-system reference and audit trail. Format: CAPEX-{YYYY}-{NNNNN}.. Valid values are `^CAPEX-[0-9]{4}-[0-9]{5}$`',
    `project_status` STRING COMMENT 'Current lifecycle state of the capital project workflow. Drives approval routing, budget release, and fixed asset capitalization triggers. [ENUM-REF-CANDIDATE: draft|pending_approval|approved|in_progress|on_hold|completed|cancelled — promote to reference product]',
    `project_type` STRING COMMENT 'Classification of the capital project by nature of work. Determines accounting treatment, depreciation schedule, and regulatory reporting category. Tenant Improvement (TI) projects may have separate amortization rules under ASC 842. [ENUM-REF-CANDIDATE: new_construction|renovation|equipment_replacement|infrastructure_upgrade|tenant_improvement|environmental_remediation|safety_compliance — promote to reference product]',
    `revised_budget_amount` DECIMAL(18,2) COMMENT 'Most recent approved revision to the original project budget, reflecting change orders, scope changes, or cost escalations. Null if no revision has been approved. Supports change order management and budget variance reporting.',
    `useful_life_years` STRING COMMENT 'Estimated useful life of the asset in years, used to calculate the annual depreciation charge upon capitalization. Set at project approval based on asset category and engineering assessment. Aligns with FASB ASC 360 and ISO 55000 asset lifecycle standards.',
    CONSTRAINT pk_capex_project PRIMARY KEY(`capex_project_id`)
) COMMENT 'Capital expenditure project record for major building improvements, equipment replacements, or infrastructure upgrades classified as CAPEX rather than OPEX. Captures project name, description, property reference, asset reference, approved budget, actual spend to date, project start and end dates, funding source, approval authority, ERP project system reference, and capitalization date. Distinct from routine work orders — CAPEX projects involve asset capitalization and fixed asset creation in the GL.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`parts_inventory` (
    `parts_inventory_id` BIGINT COMMENT 'Unique system-generated identifier for each parts inventory record in the maintenance domain. Primary key for the parts_inventory data product. Role: MASTER_RESOURCE.',
    `asset_id` BIGINT COMMENT 'Identifier of the property or building at which this parts inventory is stocked. Links the inventory record to a specific facility in the real estate portfolio. A null value may indicate a central warehouse not tied to a single property.',
    `building_asset_id` BIGINT COMMENT 'Foreign key linking to maintenance.building_asset. Business justification: Parts inventory records are often stocked specifically for particular building assets — critical spare parts for a specific HVAC unit, elevator components, or generator parts. Linking parts_inventory ',
    `chart_of_accounts_id` BIGINT COMMENT 'Foreign key linking to finance.chart_of_accounts. Business justification: Parts inventory carries a gl_account_code for inventory asset and expense classification. A validated FK to chart_of_accounts ensures correct GL coding for parts issuance journal entries, inventory va',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Parts inventory is tracked by cost center for inventory valuation and maintenance expense allocation. RE property managers require cost center on parts inventory for inventory accounting, CAM expense ',
    `warehouse_id` BIGINT COMMENT 'Identifier of the central or regional warehouse where this part is stocked, when inventory is managed at a warehouse level rather than at an individual property. Supports multi-site inventory pooling and centralized procurement strategies.',
    `annual_usage_quantity` DECIMAL(18,2) COMMENT 'Total quantity of this part consumed across all work orders in the trailing 12-month period. Used for demand forecasting, economic order quantity (EOQ) calculations, and procurement budget planning. Expressed in the parts unit of measure. Updated periodically from work order issuance records.',
    `bin_number` STRING COMMENT 'Specific bin, shelf, rack, or slot identifier within the storage location where the part is physically placed. Provides granular pick-location detail for technicians and warehouse staff. Complements storage_location for precise part retrieval.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `compatible_asset_types` STRING COMMENT 'Comma-separated list or descriptive text identifying the building equipment asset types or systems this part is compatible with (e.g., Carrier RTU-20, Trane AHU-5, York Chiller). Supports technician part selection during work order execution and preventive maintenance scheduling. Sourced from Building Engines asset compatibility records.',
    `cost_classification` STRING COMMENT 'Accounting classification indicating whether the parts use is capitalized as a Capital Expenditure (CAPEX) or expensed as an Operating Expenditure (OPEX). CAPEX parts extend asset life or add value; OPEX parts are routine maintenance consumables. Critical for financial reporting, GL coding, and compliance with FASB ASC 360 and IFRS 16.. Valid values are `capex|opex`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this parts inventory record was first created in the system. Serves as the RECORD_AUDIT_CREATED field for this MASTER_RESOURCE entity. Supports data lineage, audit trails, and SOX internal control requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the unit_cost is denominated (e.g., USD, CAD, GBP). Supports multi-currency operations for portfolios spanning multiple countries.. Valid values are `^[A-Z]{3}$`',
    `expiration_date` DATE COMMENT 'Date on which the current batch or lot of the part expires and should no longer be used. Applicable to chemicals, lubricants, sealants, and other time-sensitive consumables. Supports compliance with EPA and OSHA chemical storage regulations and FIFO inventory rotation.',
    `gl_account_code` STRING COMMENT 'General Ledger account code to which the cost of this part is posted when issued to a work order. Enables accurate financial reporting, cost center allocation, and CAPEX/OPEX segregation in the GL. Sourced from the chart of accounts in Yardi Voyager or SAP S/4HANA.. Valid values are `^[A-Z0-9-]{4,20}$`',
    `inventory_status` STRING COMMENT 'Current lifecycle status of the parts inventory record: active (available for use), inactive (temporarily not stocked), discontinued (no longer procured or used), on_order (replenishment order placed, awaiting receipt), quarantined (held pending inspection or quality review). Serves as the LIFECYCLE_STATUS for this MASTER_RESOURCE entity.. Valid values are `active|inactive|discontinued|on_order|quarantined`',
    `is_critical_spare` BOOLEAN COMMENT 'Flag indicating whether this part is designated as a critical spare — a part whose unavailability would cause significant building system downtime, tenant service disruption, or safety risk. Critical spares are subject to stricter minimum stock requirements and expedited procurement. True = critical spare; False = standard part.',
    `is_hazardous` BOOLEAN COMMENT 'Flag indicating whether this part or supply is classified as a hazardous material requiring special handling, storage, or disposal procedures (e.g., refrigerants, solvents, asbestos-containing materials). Triggers OSHA and EPA compliance workflows for storage, handling, and disposal. True = hazardous; False = non-hazardous.',
    `last_issued_date` DATE COMMENT 'Date on which this part was most recently issued from inventory to a work order or technician. Used to identify slow-moving or obsolete inventory items and to support FIFO rotation policies.',
    `last_physical_count_date` DATE COMMENT 'Date on which the most recent physical inventory count was conducted for this part at its storage location. Used to assess inventory record accuracy, schedule cycle counts, and support audit compliance. Discrepancies between physical count and system quantity trigger adjustment transactions.',
    `last_physical_count_quantity` DECIMAL(18,2) COMMENT 'Actual quantity recorded during the most recent physical inventory count for this part. Compared against quantity_on_hand to identify shrinkage, loss, or data entry errors. Expressed in the parts unit of measure.',
    `last_received_date` DATE COMMENT 'Date on which the most recent replenishment receipt was recorded for this part. Used to track procurement cycle times, validate lead_time_days accuracy, and support inventory aging analysis.',
    `lead_time_days` STRING COMMENT 'Expected number of calendar days from placement of a purchase order to receipt of the part at the storage location. Used in reorder point calculations to ensure parts are available before stock is depleted. Sourced from supplier agreements or historical procurement data.',
    `leed_compliant` BOOLEAN COMMENT 'Flag indicating whether this part or material meets LEED (Leadership in Energy and Environmental Design) sustainability criteria, such as low-VOC content, recycled material content, or regional sourcing requirements. Supports ESG reporting and green building certification maintenance. True = LEED compliant; False = not LEED compliant.',
    `manufacturer_name` STRING COMMENT 'Name of the original equipment manufacturer (OEM) or brand that produces this part. Used for warranty validation, OEM compliance requirements, and sourcing alternative suppliers when the preferred supplier is unavailable.',
    `manufacturer_part_number` STRING COMMENT 'Original Equipment Manufacturer (OEM) part number as assigned by the manufacturer. Used for cross-referencing with OEM documentation, warranty claims, and sourcing equivalent parts from alternative suppliers.',
    `maximum_stock_level` DECIMAL(18,2) COMMENT 'Upper bound of the desired inventory quantity for this part at the storage location. Prevents over-stocking and excess carrying costs. Used in conjunction with reorder_point and reorder_quantity for min/max inventory management. Expressed in the parts unit of measure.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, special handling instructions, substitution guidance, or procurement remarks related to this parts inventory record. Used by facility managers and procurement staff to capture context not covered by structured fields.',
    `part_category` STRING COMMENT 'High-level classification grouping the part into a maintenance category (e.g., HVAC, Plumbing, Electrical, Structural, Landscaping, Fire Safety, Elevator, General Supplies). Supports inventory reporting, spend analysis by trade, and CAPEX vs. OPEX classification. [ENUM-REF-CANDIDATE: HVAC|Plumbing|Electrical|Structural|Fire Safety|Elevator|Landscaping|General Supplies|Mechanical|Roofing — promote to reference product]',
    `part_description` STRING COMMENT 'Detailed narrative description of the part including specifications, dimensions, material composition, compatibility notes, and any distinguishing technical characteristics. Supports accurate procurement and technician identification during work order execution.',
    `part_name` STRING COMMENT 'Human-readable name or short title of the maintenance part, supply, or consumable (e.g., HVAC Air Filter 20x20x1, Ballast 4-Lamp T8). Serves as the IDENTITY_LABEL for this MASTER_RESOURCE entity. Used in work order fulfillment, procurement requests, and inventory reports.',
    `part_number` STRING COMMENT 'Externally-known manufacturer or supplier part number (catalogue number) that uniquely identifies the part across procurement and vendor systems. Used for purchase orders, vendor quotes, and cross-referencing with supplier catalogues. Serves as the BUSINESS_IDENTIFIER for this MASTER_RESOURCE entity.. Valid values are `^[A-Z0-9-]{3,30}$`',
    `part_type` STRING COMMENT 'Operational classification distinguishing the nature of the inventory item: part (durable replacement component), supply (non-durable maintenance supply), consumable (single-use item), tool (reusable tool tracked in inventory), chemical (cleaning or treatment chemical), equipment (small equipment unit). Drives handling, storage, and procurement workflows. Serves as the CLASSIFICATION_OR_TYPE for this MASTER_RESOURCE entity.. Valid values are `part|supply|consumable|tool|chemical|equipment`',
    `quantity_on_hand` DECIMAL(18,2) COMMENT 'Current physical quantity of the part available in the storage location at the time of the last inventory update. Expressed in the parts unit of measure. Core operational metric for work order fulfillment and procurement planning. Updated upon part issuance, receipt, and physical count adjustments.',
    `quantity_on_order` DECIMAL(18,2) COMMENT 'Total quantity of the part currently on open purchase orders placed with suppliers but not yet received into inventory. Used in min/max replenishment logic to avoid duplicate ordering and to project future stock levels.',
    `quantity_reserved` DECIMAL(18,2) COMMENT 'Quantity of the part currently reserved or allocated to open work orders but not yet physically issued. Reduces the effective available quantity for new work order assignments. Supports accurate available-to-promise calculations for maintenance scheduling.',
    `reorder_point` DECIMAL(18,2) COMMENT 'Minimum quantity threshold at which a replenishment order should be triggered for this part. When quantity_on_hand falls at or below this level, a procurement request is initiated. Expressed in the parts unit of measure. Core parameter for min/max inventory management in facility O&M operations.',
    `reorder_quantity` DECIMAL(18,2) COMMENT 'Standard quantity to be ordered when a replenishment is triggered (i.e., when quantity_on_hand reaches the reorder_point). May reflect economic order quantity (EOQ), supplier minimum order quantity (MOQ), or standard pack size. Expressed in the parts unit of measure.',
    `safety_data_sheet_number` STRING COMMENT 'Reference number or document identifier for the Safety Data Sheet (SDS) associated with this part or chemical. Required by OSHA Hazard Communication Standard (HazCom) for all hazardous materials. Enables rapid access to handling, storage, and emergency response information.',
    `shelf_life_days` STRING COMMENT 'Maximum number of days the part can be stored before it expires, degrades, or becomes unsuitable for use. Applicable to chemicals, lubricants, adhesives, and other perishable maintenance supplies. Null for non-perishable parts. Supports FIFO inventory management and waste reduction.',
    `storage_location` STRING COMMENT 'Physical location where the part is stored within the property or central warehouse (e.g., Basement Storage Room B-12, Mechanical Room 3F, Central Warehouse Bin A-04). Enables technicians to quickly locate parts during work order execution and supports physical inventory counts.',
    `supplier_part_number` STRING COMMENT 'The part number assigned by the preferred supplier in their own catalogue system. Used when placing purchase orders to ensure the correct item is ordered. May differ from the internal part_number.',
    `unit_cost` DECIMAL(18,2) COMMENT 'Standard or last-purchase cost per unit of measure for this part, expressed in the operating currency. Used for CAPEX vs. OPEX cost classification, work order cost tracking, inventory valuation, and procurement budget planning. Sensitive business financial data.',
    `unit_of_measure` STRING COMMENT 'Standard unit in which the part is counted, issued, and ordered (e.g., EA = Each, BOX = Box, CASE = Case, ROLL = Roll, GAL = Gallon, LB = Pound, FT = Linear Foot, SQF = Square Foot, PKG = Package, SET = Set). Governs quantity calculations on work orders and purchase orders. Serves as the MEASUREMENT_OR_VALUE qualifier for this MASTER_RESOURCE entity. [ENUM-REF-CANDIDATE: EA|BOX|CASE|ROLL|GAL|LB|FT|SQF|PKG|SET — 10 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this parts inventory record was most recently modified. Supports change tracking, data lineage, and audit compliance. Updated on any field change including quantity adjustments, cost updates, and status changes.',
    `warranty_expiration_date` DATE COMMENT 'Date on which the manufacturer or supplier warranty for this part expires. Applicable to durable parts and equipment components. Enables warranty claim tracking and ensures parts are replaced under warranty before expiration where applicable.',
    CONSTRAINT pk_parts_inventory PRIMARY KEY(`parts_inventory_id`)
) COMMENT 'Master record of maintenance parts, supplies, and consumables stocked at a property or central warehouse for building maintenance operations. Captures part number, description, unit of measure, current on-hand quantity, reorder point, reorder quantity, preferred supplier, unit cost, storage location, and asset compatibility. Supports parts availability for work order fulfillment, procurement planning, and min/max inventory management. SSOT for facility O&M inventory within the maintenance domain.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`sla_policy` (
    `sla_policy_id` BIGINT COMMENT 'Unique system-generated identifier for the SLA policy record. Primary key for the sla_policy data product in the maintenance domain.',
    `position_id` BIGINT COMMENT 'Foreign key linking to workforce.position. Business justification: SLA policy ownership by a defined position (Director of Facilities, Property Manager) is a real estate operations governance requirement for policy accountability, review scheduling, and escalation ro',
    `service_contract_id` BIGINT COMMENT 'Reference to the service contract or property management agreement under which this SLA policy is defined. Links the SLA policy to its governing contractual instrument managed in DocuSign CLM or Yardi Voyager.',
    `applies_to_all_properties` BOOLEAN COMMENT 'Indicates whether this SLA policy applies universally to all properties in the portfolio (True) or is scoped to specific property types, classes, or jurisdictions (False). When True, property_class and property_use_type filters are ignored.',
    `auto_escalation_enabled` BOOLEAN COMMENT 'Indicates whether the SLA policy triggers automatic escalation workflows in Building Engines when the escalation_threshold_hours is exceeded without resolution. When True, escalation notifications are sent to the designated PM or AM without manual intervention.',
    `business_hours_end` STRING COMMENT 'End time of the standard business day used for SLA measurement when measurement_window is business_hours. Expressed in HH:MM 24-hour format (e.g., 18:00). Varies by property jurisdiction and tenant lease terms.. Valid values are `^([01]?[0-9]|2[0-3]):[0-5][0-9]$`',
    `business_hours_start` STRING COMMENT 'Start time of the standard business day used for SLA measurement when measurement_window is business_hours. Expressed in HH:MM 24-hour format (e.g., 08:00). Varies by property jurisdiction and tenant lease terms.. Valid values are `^([01]?[0-9]|2[0-3]):[0-5][0-9]$`',
    `capex_opex_classification` STRING COMMENT 'Classifies the maintenance activities governed by this SLA policy as CAPEX (capital improvements), OPEX (routine operating expenditure), or both. Critical for financial reporting, GL coding in Yardi Voyager, and REIT FFO/AFFO calculations under SEC reporting requirements.. Valid values are `capex|opex|both`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this SLA policy record was first created in the system. Supports audit trail requirements under SOX Section 404 and data lineage tracking in the Databricks Silver Layer. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to monetary penalty amounts defined in this SLA policy (e.g., USD, GBP, EUR). Supports multi-jurisdiction property portfolios and international REIT reporting.. Valid values are `^[A-Z]{3}$`',
    `effective_from_date` DATE COMMENT 'Date from which this SLA policy becomes binding and enforceable for work orders and tenant service requests. Aligns with lease commencement or property management contract start dates. Supports ASC 842 and IFRS 16 lease accounting compliance.',
    `effective_to_date` DATE COMMENT 'Date on which this SLA policy expires or is superseded. Null indicates an open-ended policy with no defined expiry. Used for WALT/WALE-aligned SLA lifecycle management and multi-jurisdiction compliance reporting.',
    `escalation_level_count` STRING COMMENT 'Total number of escalation tiers defined within this SLA policy (e.g., 1 = escalate to PM, 2 = escalate to PM then AM, 3 = escalate to PM, AM, then executive). Governs the depth of the escalation chain for unresolved maintenance issues.',
    `escalation_threshold_hours` DECIMAL(18,2) COMMENT 'Number of hours after which an unresolved or unacknowledged work order is automatically escalated to the next management tier (e.g., Property Manager, Asset Manager). Supports automated escalation workflows in Building Engines and tenant satisfaction management.',
    `esg_tracking_required` BOOLEAN COMMENT 'Indicates whether maintenance activities under this SLA policy require ESG impact tracking (e.g., energy consumption, carbon emissions, water usage). Relevant for LEED-certified and BREEAM-rated buildings and REIT ESG disclosure obligations.',
    `jurisdiction_code` STRING COMMENT 'Geographic or regulatory jurisdiction code to which this SLA policy applies (e.g., US-NY, US-CA, UK, AU-NSW). Supports multi-jurisdiction property management standards and regional regulatory compliance requirements including HUD, EPA, and OSHA.. Valid values are `^[A-Z]{2,6}$`',
    `last_reviewed_date` DATE COMMENT 'Date on which this SLA policy was most recently formally reviewed and approved by the policy owner. Supports SOX audit trail requirements and ISO 55000 asset management governance documentation.',
    `measurement_window` STRING COMMENT 'Defines the time basis against which SLA response and resolution targets are measured. calendar_hours counts all hours including weekends and holidays; business_hours counts only standard operating hours; 24_7 applies continuous measurement for emergency services.. Valid values are `calendar_hours|business_hours|24_7`',
    `next_review_date` DATE COMMENT 'Scheduled date for the next formal review of this SLA policy. Calculated based on last_reviewed_date and review_frequency. Triggers review workflow notifications to the policy owner in Building Engines.',
    `notification_channel` STRING COMMENT 'Preferred communication channel for tenant notifications triggered by this SLA policy (e.g., email, SMS, tenant portal, phone). Applicable when tenant_notification_required is True. Configured in Building Engines and Salesforce CRM tenant profiles.. Valid values are `email|sms|portal|phone|all`',
    `osha_compliance_required` BOOLEAN COMMENT 'Indicates whether work orders governed by this SLA policy require OSHA safety compliance documentation and sign-off. True for life-safety systems (fire suppression, electrical, structural), hazardous materials handling, and confined space entry work.',
    `penalty_amount` DECIMAL(18,2) COMMENT 'Fixed monetary penalty amount applied per SLA breach event, expressed in the policy currency. Applicable when penalty_type is fixed_fee. Used in Yardi Voyager AR for tenant credit processing and financial reporting under FASB ASC 842.',
    `penalty_applicable` BOOLEAN COMMENT 'Indicates whether financial or contractual penalties apply when this SLA policy is breached. True when penalty terms are defined in the property management contract or lease agreement. Drives penalty calculation workflows and tenant credit processing.',
    `penalty_percentage` DECIMAL(18,2) COMMENT 'Percentage of monthly rent or service charge applied as a penalty per SLA breach event. Applicable when penalty_type is percentage_of_rent. Expressed as a decimal percentage (e.g., 2.50 = 2.5%). Used in Yardi Voyager for automated credit calculations.',
    `penalty_type` STRING COMMENT 'Type of penalty applied when this SLA policy is breached. rent_credit reduces tenant rent obligation; service_credit credits the tenants service charge account; fixed_fee applies a fixed monetary penalty; percentage_of_rent applies a percentage-based deduction. Null or none when penalty_applicable is False.. Valid values are `rent_credit|service_credit|fixed_fee|percentage_of_rent|none`',
    `policy_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the SLA policy across systems and contracts. Used in work order management, tenant service request tracking, and vendor dispatch communications. Sourced from Building Engines.. Valid values are `^SLA-[A-Z0-9]{3,20}$`',
    `policy_description` STRING COMMENT 'Free-text narrative description of the SLA policy scope, applicability conditions, and any special terms or exceptions. Provides context for property managers, asset managers, and compliance teams reviewing SLA compliance reports.',
    `policy_name` STRING COMMENT 'Human-readable name of the SLA policy (e.g., Emergency HVAC Response — Class A Office, Routine Maintenance — Residential). Used in tenant communications, reporting dashboards, and compliance documentation.',
    `policy_status` STRING COMMENT 'Current lifecycle status of the SLA policy record. active indicates the policy is currently enforced; superseded indicates it has been replaced by a newer version; draft indicates it is under review prior to activation.. Valid values are `active|inactive|draft|superseded|pending_review`',
    `policy_version` STRING COMMENT 'Version number of the SLA policy document (e.g., 1.0, 2.3). Supports policy versioning and audit trail for regulatory compliance under OSHA and SOX. Incremented when material changes are made to response or resolution targets.. Valid values are `^[0-9]+.[0-9]+(.[0-9]+)?$`',
    `preventive_maintenance_applicable` BOOLEAN COMMENT 'Indicates whether this SLA policy governs preventive maintenance (PM) schedules in addition to reactive work orders. When True, the policy applies to scheduled PM activities tracked in Building Engines, including HVAC servicing, elevator inspections, and O&M routines.',
    `priority_tier` STRING COMMENT 'Priority classification of the maintenance request or work order to which this SLA policy applies. emergency covers life-safety and critical system failures; urgent covers significant operational disruptions; routine covers standard maintenance; planned covers scheduled preventive maintenance (PM) activities.. Valid values are `emergency|urgent|routine|planned`',
    `property_class` STRING COMMENT 'Classification of the property type to which this SLA policy applies. Class A/B/C refers to commercial office grading; residential covers multifamily and single-family; mixed_use and industrial cover respective asset classes. Enables differentiated SLA standards by asset quality tier.. Valid values are `class_a|class_b|class_c|residential|mixed_use|industrial`',
    `property_use_type` STRING COMMENT 'Operational use type of the property covered by this SLA policy. Distinguishes between commercial, residential, industrial, retail, mixed-use, and hospitality assets, enabling use-type-specific SLA frameworks aligned with tenant expectations and lease obligations.. Valid values are `commercial|residential|industrial|retail|mixed_use|hospitality`',
    `region_name` STRING COMMENT 'Human-readable name of the geographic region or market to which this SLA policy applies (e.g., Northeast US, Greater London, Sydney Metro). Used for regional portfolio reporting and multi-market SLA benchmarking.',
    `request_category` STRING COMMENT 'Category of maintenance or facility service request covered by this SLA policy (e.g., HVAC, Plumbing, Electrical, Elevator, Fire Safety, Janitorial, Structural, Security). Drives routing rules and vendor dispatch in Building Engines. [ENUM-REF-CANDIDATE: hvac|plumbing|electrical|elevator|fire_safety|janitorial|structural|security|general — promote to reference product]',
    `resolution_time_target_hours` DECIMAL(18,2) COMMENT 'Target time in hours within which a maintenance issue must be fully resolved and the work order closed under this SLA policy. Measured from the time the request is logged. Drives OPEX planning and tenant satisfaction KPIs.',
    `response_time_target_hours` DECIMAL(18,2) COMMENT 'Target time in hours within which a maintenance technician or vendor must acknowledge and respond to a work order or tenant service request under this SLA policy. Measured from the time the request is logged in Building Engines. Critical for tenant satisfaction reporting and SLA compliance tracking.',
    `response_time_target_mins` STRING COMMENT 'Target response time expressed in minutes for high-precision SLA tracking, particularly for emergency priority tier requests where sub-hour targets apply (e.g., 15-minute emergency response). Complements response_time_target_hours for granular SLA measurement.',
    `review_frequency` STRING COMMENT 'Frequency at which this SLA policy is formally reviewed and updated to reflect changes in property management standards, tenant requirements, or regulatory obligations. Supports SOX internal controls and ISO 55000 asset management governance.. Valid values are `monthly|quarterly|semi_annual|annual|ad_hoc`',
    `source_system` STRING COMMENT 'Operational system of record from which this SLA policy record was sourced. Primarily Building Engines CMMS for facility operations; Yardi Voyager for property management contract-linked SLAs. Supports data lineage tracking in the Databricks Silver Layer.. Valid values are `building_engines|yardi_voyager|mri_software|manual`',
    `source_system_policy_ref` STRING COMMENT 'Native identifier of this SLA policy record in the originating source system (e.g., Building Engines internal SLA policy ID). Enables reconciliation between the Databricks Silver Layer and the operational system of record.',
    `tenant_notification_required` BOOLEAN COMMENT 'Indicates whether tenants must be proactively notified of work order status updates under this SLA policy. Supports tenant relationship management obligations in Salesforce CRM and lease compliance requirements under FASB ASC 842.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this SLA policy record was most recently modified. Tracks policy amendments, version updates, and status changes for audit compliance under SOX Section 404. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `vendor_dispatch_required` BOOLEAN COMMENT 'Indicates whether work orders under this SLA policy require external vendor dispatch rather than in-house maintenance staff. Drives vendor selection and dispatch workflows in Building Engines and procurement processes in SAP S/4HANA.',
    CONSTRAINT pk_sla_policy PRIMARY KEY(`sla_policy_id`)
) COMMENT 'Service Level Agreement policy record defining response and resolution time targets for maintenance work orders and tenant service requests by priority tier, property class, and request category. Captures SLA name, applicable property types, priority level (emergency, urgent, routine, planned), target response time, target resolution time, escalation rules, penalty terms, and effective date range. Supports multi-jurisdiction property management standards and can accommodate varying SLA frameworks across regions. Drives SLA compliance tracking and tenant satisfaction reporting.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`billable_charge` (
    `billable_charge_id` BIGINT COMMENT 'Primary key for billable_charge',
    `amenity_id` BIGINT COMMENT 'Foreign key linking to property.amenity. Business justification: Amenity operating charges (pool maintenance surcharge, amenity fee) may be billed to tenants. Amenity-level charge tracking supports amenity revenue/expense reporting and lease compliance.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: CAM charge and tenant billable charge approval by a specific employee is required for CAM reconciliation audit trails, tenant dispute resolution, and financial controls in real estate property managem',
    `ar_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ar_invoice. Business justification: Maintenance billable charges (tenant repairs, CAM charges) are invoiced through AR. The billable_charge.invoice_number is a denormalized reference to ar_invoice. This FK enables tenant billing reconci',
    `asset_id` BIGINT COMMENT 'Reference to the property at which the maintenance activity occurred and from which the billable charge is generated.',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Billable maintenance charges are allocated at the building level for multi-building assets. Building-level CAM reconciliation and operating expense reporting require linking charges to specific buildi',
    `cam_pool_id` BIGINT COMMENT 'Reference to the CAM expense pool to which this charge is assigned for proration and reconciliation. CAM pools group recoverable expenses by building, floor, or expense category per lease terms.',
    `chart_of_accounts_id` BIGINT COMMENT 'Foreign key linking to finance.chart_of_accounts. Business justification: Billable charges carry a gl_account_code for revenue recognition and CAM recovery classification. A validated FK to chart_of_accounts ensures correct income coding for AR invoicing, CAM reconciliation',
    `common_area_id` BIGINT COMMENT 'Foreign key linking to property.common_area. Business justification: CAM charges are allocated to specific common areas. Common area-level charge tracking is the foundation of CAM reconciliation, enabling landlords to justify CAM expenses to tenants.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Billable charges are allocated to cost centers for CAM pool management and property-level revenue tracking. RE controllers require cost center assignment on billable charges to correctly allocate CAM ',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Maintenance billable charges (CAM, tenant repairs) generate GL journal entries for revenue recognition and accrual accounting. RE controllers require the charge-to-journal-entry link for period-close ',
    `owner_agreement_id` BIGINT COMMENT 'Foreign key linking to owner.owner_agreement. Business justification: Owner NOI and management fee reporting: billable charges (CAM recoveries, maintenance costs) must be attributed to the governing owner agreement to compute net operating income, management fees, and o',
    `parking_id` BIGINT COMMENT 'Foreign key linking to property.parking. Business justification: Parking maintenance charges are billed to tenants or tracked as parking operating expenses. Parking-level charge tracking supports parking revenue/expense reporting and tenant parking lease billing.',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Commercial tenant charges are allocated to specific spaces. Space-level charge tracking is the foundation of CAM reconciliation and tenant billing in commercial real estate.',
    `service_contract_id` BIGINT COMMENT 'Reference to the service contract under which this charge was incurred, if the charge originates from a vendor service agreement rather than a discrete work order.',
    `tenant_id` BIGINT COMMENT 'Reference to the tenant responsible for or associated with this billable charge. Used for CAM charge-back processing and tenant billing under NNN or modified gross lease structures.',
    `tenant_occupancy_id` BIGINT COMMENT 'Foreign key linking to tenant.occupancy. Business justification: CAM reconciliation, tenant-billable repair invoicing, and pro-rata share calculations require linking charges to the specific occupancy period. Property accountants need occupancy_id to validate that ',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Tenant-billable maintenance charges are allocated to specific units. Unit-level charge history supports lease administration, tenant billing disputes, and move-out cost reconciliation.',
    `vendor_dispatch_id` BIGINT COMMENT 'Foreign key linking to maintenance.vendor_dispatch. Business justification: Billable charges to tenants are frequently generated from vendor dispatch events — when a vendor performs work and submits an invoice, the cost may be recoverable from the tenant under CAM provisions ',
    `vendor_id` BIGINT COMMENT 'Reference to the external vendor or contractor who performed the maintenance service that generated this charge. Used for vendor spend analysis, AP reconciliation, and service contract compliance.',
    `work_order_id` BIGINT COMMENT 'Reference to the originating work order in Building Engines that generated this billable charge. Links the maintenance activity to the recoverable cost.',
    `approval_date` DATE COMMENT 'Date on which the billable charge was approved by the property manager or asset manager for tenant invoicing. Part of the internal controls audit trail.',
    `billing_period_end_date` DATE COMMENT 'End date of the billing period to which this charge is allocated. Together with billing_period_start_date defines the CAM reconciliation window for this charge.',
    `billing_period_start_date` DATE COMMENT 'Start date of the billing period to which this charge is allocated. Used in CAM reconciliation to match charges to the correct annual or monthly reconciliation cycle.',
    `cam_allocation_method` STRING COMMENT 'Method used to allocate the CAM pool charge to this tenant. Pro-rata NLA/GLA allocates based on the tenants proportionate share of leasable area; fixed percentage uses a lease-defined rate; direct assignment charges the full amount to one tenant.. Valid values are `pro_rata_nla|pro_rata_gla|fixed_percentage|direct_assignment|square_footage`',
    `charge_category` STRING COMMENT 'Classification of the maintenance activity type that generated this billable charge. Used for CAM pool segmentation, tenant billing transparency, and OPEX vs. CAPEX reporting. [ENUM-REF-CANDIDATE: HVAC|janitorial|repairs|landscaping|security|electrical|plumbing|pest_control|elevator|general_maintenance — promote to reference product]',
    `charge_date` DATE COMMENT 'The principal business event date on which the billable maintenance charge was incurred or the service was rendered. Used as the basis for billing period assignment and CAM pool allocation.',
    `charge_number` STRING COMMENT 'Externally-visible, human-readable charge reference number used in tenant invoices, CAM reconciliation statements, and property management accounting systems such as Yardi Voyager AR. Format: BC-YYYY-NNNNNN.. Valid values are `^BC-[0-9]{4}-[0-9]{6}$`',
    `charge_status` STRING COMMENT 'Current lifecycle state of the billable charge from creation through collection or write-off. Drives workflow routing in Yardi Voyager AR and CAM reconciliation processing. [ENUM-REF-CANDIDATE: draft|pending_approval|approved|invoiced|collected|disputed|written_off|voided — promote to reference product]',
    `charge_type` STRING COMMENT 'Distinguishes the nature of the billable charge: CAM recoverable (pooled allocation), direct tenant charge (tenant-caused damage or exclusive service), capital improvement (CAPEX), emergency response, or warranty claim. Drives GL coding and lease compliance.. Valid values are `cam_recoverable|direct_tenant|capital_improvement|emergency|warranty_claim`',
    `cost_classification` STRING COMMENT 'Indicates whether the maintenance charge is classified as an Operating Expenditure (OPEX) or Capital Expenditure (CAPEX) per accounting policy. Critical for financial reporting, asset lifecycle tracking, and REIT compliance under FASB and IFRS standards.. Valid values are `OPEX|CAPEX`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this billable charge record was first created in the system. Provides the audit trail creation marker for data governance and SOX compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this charge record (e.g., USD, CAD, GBP). Supports multi-currency portfolio operations for international real estate portfolios.. Valid values are `^[A-Z]{3}$`',
    `dispute_date` DATE COMMENT 'Date on which the tenant formally raised a dispute against this charge. Used to track dispute resolution timelines and SLA compliance for tenant relations.',
    `dispute_reason` STRING COMMENT 'Free-text description of the tenants stated reason for disputing this charge. Populated when charge_status is disputed. Used for dispute resolution tracking and lease compliance review.',
    `estimated_cam_paid` DECIMAL(18,2) COMMENT 'Total estimated CAM payments already collected from the tenant during the reconciliation period. Used to calculate the reconciliation true-up amount (over- or under-collection) at year-end.',
    `gl_account_code` STRING COMMENT 'General Ledger account code in Yardi Voyager or SAP S/4HANA to which this billable charge is posted. Determines the financial statement classification (revenue, expense recovery, or liability) for the charge.',
    `gross_charge_amount` DECIMAL(18,2) COMMENT 'Total gross cost of the maintenance activity before any tenant allocation, CAM pool proration, or adjustments. Represents the full vendor invoice or internal cost amount in the propertys operating currency.',
    `invoice_date` DATE COMMENT 'Date on which the tenant invoice containing this charge was issued. Used for payment due date calculation and aging analysis in Accounts Receivable.',
    `is_cam_reconciliation_charge` BOOLEAN COMMENT 'Indicates whether this charge is part of an annual CAM reconciliation adjustment (true) or a current-period direct billing (false). CAM reconciliation charges arise when actual expenses differ from estimated CAM payments collected during the year.',
    `lease_structure_type` STRING COMMENT 'The lease structure under which this charge is recoverable from the tenant. NNN (Triple Net) leases pass through all operating expenses; modified gross leases recover specific categories; gross leases are typically non-recoverable. Determines billing eligibility.. Valid values are `NNN|modified_gross|gross|full_service|double_net`',
    `notes` STRING COMMENT 'Free-text field for property managers to record additional context, special billing instructions, or explanatory notes related to this charge. Visible in tenant-facing CAM reconciliation statements.',
    `payment_due_date` DATE COMMENT 'Date by which the tenant is required to remit payment for this charge per the lease agreement terms. Used for AR aging, late fee assessment, and cash flow forecasting.',
    `reconciliation_year` STRING COMMENT 'The calendar or fiscal year for which the CAM reconciliation is being performed. Applicable only when is_cam_reconciliation_charge is true. Used to match reconciliation charges to the correct operating year.',
    `resolution_date` DATE COMMENT 'Date on which a disputed charge was resolved, either through adjustment, credit, or confirmation of the original amount. Marks the closure of the dispute lifecycle.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this billable charge record originated. Supports data lineage tracking and reconciliation between Building Engines CMMS and Yardi Voyager AR.. Valid values are `Building_Engines|Yardi_Voyager|MRI_Software|SAP_S4HANA|Manual`',
    `source_system_charge_code` STRING COMMENT 'The native identifier of this charge record in the originating source system (e.g., Building Engines charge ID or Yardi Voyager transaction ID). Used for data lineage, reconciliation, and deduplication in the Silver Layer.',
    `tax_amount` DECIMAL(18,2) COMMENT 'Applicable sales or use tax assessed on the billable maintenance charge, where required by jurisdiction. Included in the tenant invoice and tracked separately for tax remittance compliance.',
    `tenant_allocated_amount` DECIMAL(18,2) COMMENT 'The portion of the gross charge amount allocated to the specific tenant after applying the CAM pool allocation method (pro-rata share, fixed percentage, or direct assignment). This is the net amount billed to the tenant.',
    `tenant_pro_rata_share` DECIMAL(18,2) COMMENT 'The tenants proportionate share of the CAM pool expressed as a decimal fraction (e.g., 0.125000 = 12.5%). Derived from the ratio of the tenants Net Leasable Area (NLA) to the total building NLA or applicable pool area as defined in the lease.',
    `total_invoiced_amount` DECIMAL(18,2) COMMENT 'Net total amount invoiced to the tenant, equal to the tenant_allocated_amount plus tax_amount. Represents the final receivable amount recorded in Yardi Voyager AR for this charge.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this billable charge record. Used for incremental data pipeline processing in the Databricks Silver Layer and audit trail compliance.',
    `vendor_invoice_number` STRING COMMENT 'The vendors own invoice reference number for the maintenance service. Used to reconcile the billable charge against the corresponding Accounts Payable entry in Yardi Voyager AP.',
    CONSTRAINT pk_billable_charge PRIMARY KEY(`billable_charge_id`)
) COMMENT 'Billable maintenance charge record generated when maintenance costs are recoverable from tenants under NNN or modified gross lease structures as part of CAM reconciliation. Captures the originating work order or service contract, tenant reference, charge amount, charge category (HVAC, janitorial, repairs, landscaping), billing period, CAM pool allocation method, and invoice reference in the property management accounting system. Bridges the maintenance domain to the finance and lease domains for CAM charge-back processing.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`safety_incident` (
    `safety_incident_id` BIGINT COMMENT 'Unique system-generated identifier for each safety incident or near-miss event recorded at a managed property. Primary key for the safety_incident data product.',
    `amenity_id` BIGINT COMMENT 'Foreign key linking to property.amenity. Business justification: Amenity-related incidents (pool drowning, gym injury, playground accident) are a distinct liability category. Amenity-level incident tracking supports insurance, regulatory reporting, and amenity risk',
    `asset_id` BIGINT COMMENT 'Reference to the managed property where the safety incident occurred. Links to the property master record in the property domain, sourced from Yardi Voyager or Building Engines property registry.',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Safety incidents occur in specific buildings. Building-level incident rate reporting is required for OSHA compliance, insurance underwriting, ESG disclosure, and building safety certification.',
    `claim_id` BIGINT COMMENT 'Foreign key linking to insurance.claim. Business justification: OSHA-recordable safety incidents on property directly generate workers comp or general liability insurance claims. Real estate risk managers track the incident-to-claim lifecycle for loss run analysis',
    `common_area_id` BIGINT COMMENT 'Foreign key linking to property.common_area. Business justification: Slip-and-fall and other common area incidents are a major liability category. Linking incidents to specific common areas supports insurance claims, ADA compliance audits, and litigation defense.',
    `violation_id` BIGINT COMMENT 'Foreign key linking to compliance.violation. Business justification: Safety incidents result in compliance violation citations (OSHA citations, local code violations). Compliance officers tracking penalty exposure and abatement deadlines need to link the incident to th',
    `employee_id` BIGINT COMMENT 'Reference to the person involved in the safety incident (employee, contractor, tenant, or visitor). Links to the workforce or tenant party record. Nullable for near-miss events with no injured party.',
    `osha_incident_id` BIGINT COMMENT 'Foreign key linking to compliance.osha_incident. Business justification: A maintenance safety incident generates an OSHA regulatory filing record. Safety managers must link the internal incident record to the compliance OSHA record for OSHA 300 log management, workers com',
    `parking_id` BIGINT COMMENT 'Foreign key linking to property.parking. Business justification: Parking incidents (vehicle damage, slip-and-fall in parking garage, carbon monoxide exposure) are a major liability category. Parking-level incident tracking supports insurance claims and safety repor',
    `pm_execution_id` BIGINT COMMENT 'Foreign key linking to maintenance.pm_execution. Business justification: Safety incidents can occur during the execution of preventive maintenance tasks. pm_execution already tracks safety_hazard_identified (BOOLEAN) and osha_incident_report_number (STRING), confirming tha',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Safety incidents in commercial spaces (electrical fire in a suite, chemical spill in a lab space) require space-level tracking for insurance claims, OSHA reporting, and tenant liability determination.',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Safety incidents in residential units (gas leak, electrical fire, slip-and-fall) require unit-level tracking for habitability compliance, insurance claims, and regulatory reporting.',
    `work_order_id` BIGINT COMMENT 'Reference to the maintenance work order or tenant service request that was in progress at the time of the safety incident, if applicable. Links to the work order record in Building Engines CMMS.',
    `body_part_affected` STRING COMMENT 'The specific body part injured or affected in the safety incident, as required for OSHA 300 log recordkeeping. Examples include head, back, hand, foot, eye. Nullable for non-injury incident types such as near-miss or property damage.',
    `capex_opex_classification` STRING COMMENT 'Financial classification of the remediation or corrective action costs associated with the safety incident. CAPEX applies when the corrective action results in a capital improvement (e.g., equipment replacement, structural modification); OPEX applies for routine repairs and maintenance. Supports financial reporting and asset management under FASB ASC 360.. Valid values are `capex|opex|not_applicable`',
    `closure_notes` STRING COMMENT 'Free-text notes recorded at the time of incident closure, summarizing the final outcome, verification of corrective actions, and any residual risk considerations. Provides a complete audit trail for the incident lifecycle.',
    `contributing_factors` STRING COMMENT 'Narrative description of secondary or contributing factors that contributed to the safety incident beyond the primary root cause. May include environmental conditions, time pressure, staffing levels, or equipment age. Supports comprehensive incident investigation.',
    `corrective_action_completed_date` DATE COMMENT 'Actual date on which all corrective and preventive actions were completed and verified. Null if corrective actions are still pending. Used to measure remediation timeliness and close the incident lifecycle.',
    `corrective_action_due_date` DATE COMMENT 'Target completion date by which all corrective and preventive actions identified in the incident investigation must be implemented. Used for tracking remediation progress and accountability.',
    `corrective_actions` STRING COMMENT 'Description of the corrective and preventive actions taken or planned in response to the safety incident to prevent recurrence. May include equipment repair, procedural updates, additional training, or physical modifications to the facility.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when the safety incident record was first created in the system. Used for data lineage and audit trail purposes.',
    `days_away_from_work` STRING COMMENT 'Number of calendar days the injured party was away from work as a result of the safety incident. Required for OSHA 300 log (Column K) and OSHA 300A annual summary. Zero for incidents not resulting in lost time.',
    `days_job_transfer_restriction` STRING COMMENT 'Number of calendar days the injured party was on job transfer or work restriction as a result of the safety incident. Required for OSHA 300 log (Column L). Distinct from days_away_from_work.',
    `equipment_involved` STRING COMMENT 'Description or identifier of the building equipment, machinery, or system involved in the safety incident, such as HVAC unit, elevator, electrical panel, or scaffolding. Supports equipment lifecycle analysis and O&M safety reviews.',
    `esg_reportable` BOOLEAN COMMENT 'Indicates whether the safety incident is material for ESG reporting purposes, including sustainability disclosures, GRESB assessments, or SEC climate and social risk disclosures for publicly traded REITs. Supports ESG portfolio-level safety metrics.',
    `estimated_remediation_cost` DECIMAL(18,2) COMMENT 'Estimated total cost of corrective actions and remediation activities required to address the safety incident, expressed in the local currency. Used for CAPEX/OPEX budgeting and insurance claim estimation. Sourced from Building Engines work order cost estimates.',
    `incident_category` STRING COMMENT 'Secondary classification providing more granular categorization of the incident type, such as slip/trip/fall, struck-by object, electrical hazard, chemical exposure, equipment failure, or structural failure. [ENUM-REF-CANDIDATE: slip_trip_fall|struck_by|electrical|chemical_exposure|equipment_failure|structural|ergonomic|fire_explosion|environmental_release|other — promote to reference product]',
    `incident_description` STRING COMMENT 'Detailed narrative description of the safety incident or near-miss event, including what happened, the sequence of events, conditions at the time, and any immediate actions taken. Free-text field captured by the reporting party.',
    `incident_location_detail` STRING COMMENT 'Specific location within the property where the incident occurred, such as floor number, suite, common area, rooftop, parking garage, mechanical room, or stairwell. Complements the property_id with sub-property granularity.',
    `incident_number` STRING COMMENT 'Externally-known, human-readable reference number assigned to the safety incident at the time of reporting. Used for cross-referencing with regulatory filings, insurance claims, and Building Engines work order records. Format: INC-YYYY-NNNNNN.. Valid values are `^INC-[0-9]{4}-[0-9]{6}$`',
    `incident_status` STRING COMMENT 'Current workflow state of the safety incident record, tracking its lifecycle from initial report through investigation, corrective action, and closure. Valid values: open, under_investigation, corrective_action_pending, closed, voided.. Valid values are `open|under_investigation|corrective_action_pending|closed|voided`',
    `incident_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the safety incident or near-miss event occurred at the property. This is the principal real-world event timestamp, distinct from the record creation timestamp. Stored in ISO 8601 format with timezone offset.',
    `incident_type` STRING COMMENT 'Primary classification of the safety incident by nature of the event. Drives regulatory recordability determination and reporting pathway. Valid values: injury, near_miss, property_damage, environmental, fire, security.. Valid values are `injury|near_miss|property_damage|environmental|fire|security`',
    `injured_party_type` STRING COMMENT 'Classification of the person involved in the safety incident by their relationship to the property or organization. Determines applicable regulatory reporting obligations and insurance coverage. Valid values: employee, contractor, tenant, visitor, vendor.. Valid values are `employee|contractor|tenant|visitor|vendor`',
    `injury_nature` STRING COMMENT 'Description of the nature of the injury or occupational illness sustained, such as laceration, fracture, sprain, burn, or respiratory condition. Required for OSHA 300 log and workers compensation filings. [ENUM-REF-CANDIDATE: laceration|fracture|sprain_strain|burn|contusion|respiratory|eye_injury|amputation|fatality|other — promote to reference product]',
    `investigating_officer` STRING COMMENT 'Name or identifier of the property manager, safety officer, or facility operations lead responsible for conducting the incident investigation. Supports accountability and audit trail for the investigation process.',
    `investigation_completed_date` DATE COMMENT 'Date on which the formal incident investigation was completed and findings were documented. Marks the transition from investigation to corrective action phase in the incident lifecycle.',
    `is_environmental_release` BOOLEAN COMMENT 'Indicates whether the safety incident involved a release of hazardous materials, chemicals, or pollutants into the environment. Triggers EPA reporting obligations and environmental compliance review when True.',
    `is_osha_recordable` BOOLEAN COMMENT 'Indicates whether the safety incident meets OSHA recordability criteria under 29 CFR Part 1904 and must be entered on the OSHA 300 log. True if the incident resulted in medical treatment beyond first aid, days away from work, restricted work, job transfer, loss of consciousness, or diagnosis of a significant injury by a healthcare professional.',
    `is_riddor_reportable` BOOLEAN COMMENT 'Indicates whether the safety incident is reportable under the UK Reporting of Injuries, Diseases and Dangerous Occurrences Regulations 2013 (RIDDOR). Applicable for properties under UK jurisdiction. Null for non-UK properties.',
    `osha_300_log_entry_date` DATE COMMENT 'The date on which the safety incident was entered onto the OSHA 300 log. OSHA requires recordable incidents to be logged within seven calendar days of receiving information that a recordable case occurred. Nullable for non-OSHA-recordable incidents.',
    `regulatory_jurisdiction` STRING COMMENT 'The country jurisdiction governing the regulatory reporting obligations for this safety incident. Determines which reporting framework applies (OSHA 300 for USA, RIDDOR for GBR, etc.). Uses ISO 3166-1 alpha-3 country codes. [ENUM-REF-CANDIDATE: USA|GBR|CAN|AUS|DEU|FRA|SGP|ARE|OTHER — 9 candidates stripped; promote to reference product]',
    `reported_by` STRING COMMENT 'Name or identifier of the person who initially reported the safety incident to the facility management team. May be the injured party, a witness, or a property manager. Supports incident reporting accountability.',
    `reported_timestamp` TIMESTAMP COMMENT 'Date and time when the safety incident was formally reported to the facility management team or entered into the Building Engines CMMS system. May differ from incident_timestamp due to delayed reporting.',
    `root_cause` STRING COMMENT 'The identified root cause of the safety incident as determined through investigation. Describes the underlying systemic or behavioral factor that allowed the incident to occur, such as inadequate PPE, equipment malfunction, procedural non-compliance, or environmental hazard.',
    `treatment_type` STRING COMMENT 'Classification of the medical treatment provided following the safety incident. Determines OSHA recordability: first aid cases are generally not OSHA recordable, while medical treatment beyond first aid triggers recordability. Valid values: first_aid, medical_treatment, hospitalization, fatality, no_treatment.. Valid values are `first_aid|medical_treatment|hospitalization|fatality|no_treatment`',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when the safety incident record was most recently modified. Tracks changes to investigation findings, corrective actions, or regulatory filing status.',
    `witness_names` STRING COMMENT 'Names of individuals who witnessed the safety incident. Recorded as a comma-separated list or narrative. Used during incident investigation and may be required for regulatory filings or legal proceedings. Classified as confidential due to sensitivity of witness information.',
    CONSTRAINT pk_safety_incident PRIMARY KEY(`safety_incident_id`)
) COMMENT 'Safety incident or near-miss event occurring at a managed property during maintenance or facility operations activities. Captures incident date and time, property location, incident type (injury, near-miss, property damage, environmental), description, injured party details, regulatory recordability flag (OSHA 300 log in US, RIDDOR in UK, or equivalent jurisdiction-specific reporting), first aid vs. medical treatment classification, root cause, corrective actions taken, and regulatory filing reference. Supports workplace safety compliance and building safety governance across jurisdictions.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`pm_execution` (
    `pm_execution_id` BIGINT COMMENT 'Unique system-generated identifier for each preventive maintenance execution record. Primary key for the pm_execution data product in the maintenance domain.',
    `building_asset_id` BIGINT COMMENT 'Foreign key linking to maintenance.building_asset. Business justification: PM executions are performed on specific physical building assets (HVAC units, elevators, fire suppression systems). While pm_execution already links to property.asset (cross-domain), a direct FK to ma',
    `chart_of_accounts_id` BIGINT COMMENT 'Foreign key linking to finance.chart_of_accounts. Business justification: PM executions carry a gl_account_code for expense classification. A validated FK to chart_of_accounts ensures correct GL coding for maintenance expense posting, CAM recoverability determination, and L',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: PM executions record actual labor and parts costs that must be allocated to cost centers for property-level expense posting. RE controllers require cost center on PM executions for GL posting, CAM exp',
    `employee_id` BIGINT COMMENT 'Reference to the technician or maintenance staff member assigned to and responsible for executing this PM task. Supports workforce productivity and compliance tracking.',
    `pm_schedule_id` BIGINT COMMENT 'Reference to the parent PM schedule that triggered this execution instance. Links the execution record back to the recurring schedule definition from which it was generated.',
    `asset_id` BIGINT COMMENT 'Reference to the property at which this preventive maintenance execution was performed. Enables property-level PM compliance tracking and CAPEX/OPEX reporting.',
    `work_order_id` BIGINT COMMENT 'Reference to the associated work order record in Building Engines that corresponds to this PM execution instance. Provides traceability between the PM execution and the formal work order workflow.',
    `service_contract_id` BIGINT COMMENT 'Reference to the service contract under which this PM execution was performed, if applicable. Links the execution to vendor service agreements for contract compliance tracking and invoice reconciliation.',
    `actual_duration_minutes` STRING COMMENT 'The actual time in minutes taken to complete the PM execution, derived from start and end timestamps or manually entered by the technician. Compared against planned_duration_minutes for variance analysis and OPEX labor cost tracking.',
    `asset_condition_after` STRING COMMENT 'Technician-assessed condition rating of the asset immediately after the PM execution was completed. Compared against asset_condition_before to measure maintenance effectiveness and inform asset replacement decisions.. Valid values are `excellent|good|fair|poor|critical`',
    `asset_condition_before` STRING COMMENT 'Technician-assessed condition rating of the asset immediately before the PM execution commenced. Provides a baseline for measuring the impact of preventive maintenance on asset condition and supports equipment lifecycle analysis.. Valid values are `excellent|good|fair|poor|critical`',
    `checklist_completion_pct` DECIMAL(18,2) COMMENT 'Percentage of applicable checklist items (excluding N/A) that were completed (pass or fail) during this PM execution. Calculated as (passed + failed) / (total - na) * 100. Key metric for PM compliance reporting and regulatory audit readiness.',
    `checklist_failed_items` STRING COMMENT 'Number of checklist task items that received a fail result during this PM execution. A non-zero value typically triggers a corrective work order. Key indicator for equipment condition deterioration and OSHA safety compliance.',
    `checklist_na_items` STRING COMMENT 'Number of checklist task items marked as not applicable (N/A) during this PM execution, typically due to equipment configuration, seasonal conditions, or scope exclusions. Ensures accurate completion rate calculations.',
    `checklist_passed_items` STRING COMMENT 'Number of checklist task items that received a pass result during this PM execution. Used to calculate pass rate and assess overall equipment condition at time of inspection.',
    `checklist_total_items` STRING COMMENT 'Total number of checklist task items defined for this PM execution, as inherited from the parent PM schedule template. Provides the denominator for checklist completion rate calculations.',
    `corrective_wo_spawned` BOOLEAN COMMENT 'Indicates whether a corrective work order was generated as a result of findings identified during this PM execution. True when one or more checklist items failed or findings warranted follow-up corrective action.',
    `cost_classification` STRING COMMENT 'Classification of the maintenance activity cost as Capital Expenditure (CAPEX), Operating Expenditure (OPEX), or a mixed allocation. Drives general ledger (GL) coding and financial reporting under FASB ASC 360 and IFRS 16 standards.. Valid values are `capex|opex|mixed`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this PM execution record was first created in the source system (Building Engines CMMS). Provides the audit trail creation anchor for data lineage and compliance reporting.',
    `end_timestamp` TIMESTAMP COMMENT 'The precise date and time when the technician completed the PM task. Used with start_timestamp to derive actual duration for labor reporting and equipment reliability analysis.',
    `equipment_category` STRING COMMENT 'The category of building equipment or system on which the PM was performed (e.g., HVAC, Electrical, Plumbing, Elevator, Fire Safety, Roofing). Enables category-level PM compliance reporting and O&M cost analysis. [ENUM-REF-CANDIDATE: hvac|electrical|plumbing|elevator|fire_safety|roofing|structural|mechanical|it_infrastructure|landscaping — promote to reference product]',
    `execution_date` DATE COMMENT 'The actual calendar date on which the preventive maintenance task was performed. Compared against scheduled_date to measure schedule compliance and variance.',
    `execution_number` STRING COMMENT 'Externally visible, human-readable reference number for this PM execution record as assigned by the Building Engines CMMS (e.g., PME-2024-00123). Used for cross-system reference, audit trails, and field technician communication.',
    `execution_status` STRING COMMENT 'Current lifecycle status of the PM execution record. completed indicates all checklist items were addressed; in_progress indicates work has started but not finished; skipped indicates the task was intentionally bypassed with justification; cancelled indicates the task was voided; overdue indicates the scheduled date passed without completion.. Valid values are `completed|in_progress|skipped|cancelled|overdue`',
    `findings_notes` STRING COMMENT 'Free-text field capturing observations, anomalies, deficiencies, or notable conditions identified by the technician during the PM execution. Provides qualitative context for failed checklist items and informs corrective action decisions.',
    `gl_account_code` STRING COMMENT 'The General Ledger account code to which the costs of this PM execution are posted in the financial system (Yardi Voyager or SAP S/4HANA). Ensures accurate financial reporting and CAPEX/OPEX segregation.',
    `labor_cost` DECIMAL(18,2) COMMENT 'Total labor cost associated with this PM execution, calculated from technician hours and applicable labor rates. Used for OPEX tracking, maintenance budget variance analysis, and total cost of ownership (TCO) reporting.',
    `leed_compliance_relevant` BOOLEAN COMMENT 'Indicates whether this PM execution contributes to LEED certification maintenance requirements (e.g., HVAC filter changes, energy system inspections). Supports ESG reporting and green building certification compliance tracking.',
    `meter_reading_unit` STRING COMMENT 'The unit of measure for the meter_reading_value recorded at PM execution (e.g., hours for run-hour meters, cycles for compressor cycle counters, kWh for energy meters). Ensures correct interpretation of meter data for scheduling and MTBF calculations.. Valid values are `hours|cycles|miles|kilometers|starts|kwh`',
    `meter_reading_value` DECIMAL(18,2) COMMENT 'The equipment meter or usage counter reading recorded at the time of PM execution (e.g., run hours, cycle count, mileage). Used for meter-based PM scheduling and equipment lifecycle tracking. Null for time-based PM types.',
    `osha_incident_report_number` STRING COMMENT 'The OSHA incident report reference number generated when a safety hazard is identified during the PM execution. Populated only when safety_hazard_identified is True. Supports regulatory compliance tracking and audit documentation.',
    `overall_result` STRING COMMENT 'The overall outcome assessment of the PM execution. pass indicates all applicable items passed; fail indicates one or more critical items failed; conditional_pass indicates minor findings noted but asset is operational; incomplete indicates the checklist was not fully completed.. Valid values are `pass|fail|conditional_pass|incomplete`',
    `parts_consumed_count` STRING COMMENT 'Total number of distinct part line items consumed during this PM execution. Provides a summary count for inventory reconciliation and OPEX/CAPEX classification of maintenance activities.',
    `parts_cost` DECIMAL(18,2) COMMENT 'Total cost of all parts and materials consumed during this PM execution, in the local operating currency. Used for OPEX vs. CAPEX classification, maintenance budget tracking, and asset lifecycle cost analysis.',
    `planned_duration_minutes` STRING COMMENT 'The estimated time in minutes allocated for completing this PM task as defined in the parent PM schedule. Used to compare against actual duration for labor efficiency and scheduling accuracy analysis.',
    `pm_type` STRING COMMENT 'Classification of the PM execution by its triggering methodology. time_based is calendar-driven; meter_based is triggered by usage readings (e.g., run hours); condition_based is triggered by sensor thresholds; seasonal is tied to seasonal cycles; regulatory is mandated by code or regulation.. Valid values are `time_based|meter_based|condition_based|seasonal|regulatory`',
    `regulatory_inspection_flag` BOOLEAN COMMENT 'Indicates whether this PM execution fulfills a mandatory regulatory inspection requirement (e.g., fire suppression system inspection, elevator safety inspection, boiler certification). When True, the execution record serves as compliance evidence for regulatory reporting.',
    `regulatory_reference_code` STRING COMMENT 'The specific regulatory code, standard, or permit number that this PM execution satisfies (e.g., NFPA 25, OSHA 1910.217, local fire code section). Populated when regulatory_inspection_flag is True. Supports compliance documentation and audit evidence.',
    `safety_hazard_identified` BOOLEAN COMMENT 'Indicates whether a safety hazard was identified during the PM execution. When True, triggers mandatory OSHA-compliant incident reporting and escalation workflows. Critical for regulatory compliance and building safety management.',
    `scheduled_date` DATE COMMENT 'The planned calendar date on which this PM execution was scheduled to occur, as derived from the parent PM schedule. Used to measure schedule adherence and calculate overdue status.',
    `start_timestamp` TIMESTAMP COMMENT 'The precise date and time when the technician began executing the PM task. Used in conjunction with end_timestamp to calculate actual duration and support MTBF and labor efficiency analysis.',
    `supervisor_approval_timestamp` TIMESTAMP COMMENT 'The date and time when a supervisor approved the PM execution record. Populated when supervisor_approved is True. Provides an audit trail for quality assurance and regulatory compliance sign-off.',
    `supervisor_approved` BOOLEAN COMMENT 'Indicates whether a supervisor or property manager (PM) has reviewed and approved the completed PM execution record. Required for quality assurance workflows and regulatory compliance sign-off.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this PM execution record was last modified in the source system. Supports data lineage tracking, change auditing, and incremental data pipeline processing in the Databricks Silver Layer.',
    CONSTRAINT pk_pm_execution PRIMARY KEY(`pm_execution_id`)
) COMMENT 'Execution record of a completed preventive maintenance task instance generated from a PM schedule. Captures the parent PM schedule reference, execution date, technician assigned, actual vs. planned duration, checklist completion status (each task item pass/fail/N/A), findings noted, and parts consumed. Records whether a corrective work order was spawned from findings. Provides the historical audit trail of PM compliance and supports equipment reliability analysis and mean-time-between-failure (MTBF) calculations.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`energy_meter` (
    `energy_meter_id` BIGINT COMMENT 'Unique surrogate identifier for the energy meter master record in the lakehouse silver layer. Primary key for this entity.',
    `amenity_id` BIGINT COMMENT 'Foreign key linking to property.amenity. Business justification: Amenities (pools, gyms, common lounges) have dedicated energy meters for amenity cost allocation. Amenity-level energy metering is used in high-end commercial and mixed-use properties for amenity oper',
    `asset_id` BIGINT COMMENT 'Reference to the managed property at which this meter is installed. Used to associate utility consumption and cost allocation to a specific asset in the portfolio.',
    `building_asset_id` BIGINT COMMENT 'Reference to the specific building asset record (from maintenance.building_asset) representing the physical structure or equipment system to which this meter is attached, enabling asset lifecycle and condition tracking.',
    `building_id` BIGINT COMMENT 'Foreign key linking to property.building. Business justification: Energy meters are installed in specific buildings. Building-level energy consumption reporting for Energy Star benchmarking, LEED certification, and ESG disclosure requires linking meters to buildings',
    `chart_of_accounts_id` BIGINT COMMENT 'Foreign key linking to finance.chart_of_accounts. Business justification: Energy meters carry a gl_account_code for utility expense posting. A validated FK to chart_of_accounts ensures correct GL coding for utility AP invoices, CAM utility recovery, and ENERGY STAR/ESG util',
    `common_area_id` BIGINT COMMENT 'Foreign key linking to property.common_area. Business justification: Common area meters track energy consumption for CAM cost allocation. Linking meters to specific common areas supports accurate CAM reconciliation and common area energy efficiency reporting.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Energy meters are assigned to cost centers for utility expense allocation and CAM recovery calculations. RE property accountants require cost center on energy meters for utility billing reconciliation',
    `parent_meter_energy_meter_id` BIGINT COMMENT 'Self-referencing identifier pointing to the parent (master) meter in a hierarchical metering configuration. Null for top-level main meters. Enables submeter-to-master reconciliation for tenant utility cost allocation and loss/variance analysis.',
    `parking_id` BIGINT COMMENT 'Foreign key linking to property.parking. Business justification: Parking facilities have dedicated meters for lighting and EV charging energy consumption. Parking-level energy cost tracking supports parking revenue/expense reporting and EV infrastructure cost alloc',
    `space_id` BIGINT COMMENT 'Foreign key linking to property.space. Business justification: Commercial spaces have dedicated sub-meters for tenant utility billing and green lease compliance. Space-level metering data supports CAM reconciliation and LEED/BREEAM energy reporting. Existing suit',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Energy meters are required by mandatory sub-metering laws and energy benchmarking ordinances (NYC Local Law 87, EU Energy Efficiency Directive). Compliance officers link meters to the regulatory oblig',
    `service_contract_id` BIGINT COMMENT 'Reference to the maintenance service contract covering calibration, repair, or monitoring services for this meter. Links to maintenance.service_contract for vendor SLA tracking and OPEX cost classification.',
    `suite_unit_id` BIGINT COMMENT 'Reference to the specific leasable suite or unit served by this meter, enabling direct tenant utility cost allocation and submeter reconciliation against master meter readings.',
    `unit_id` BIGINT COMMENT 'Foreign key linking to property.unit. Business justification: Sub-metering at the unit level is standard in multi-family and commercial properties for tenant utility billing. Unit-level energy consumption tracking is required for utility billing, green leases, a',
    `replaced_energy_meter_id` BIGINT COMMENT 'Self-referencing FK on energy_meter (replaced_energy_meter_id)',
    `building_engines_meter_code` STRING COMMENT 'The native meter identifier in the Building Engines CMMS source system. Used for data lineage, reconciliation between the lakehouse silver layer and the operational system of record, and troubleshooting ETL discrepancies.',
    `cam_billable` BOOLEAN COMMENT 'Indicates whether utility costs recorded by this meter are included in the Common Area Maintenance (CAM) expense pool for tenant pro-rata billing. Critical for NNN and gross lease CAM reconciliation under FASB ASC 842.',
    `communication_protocol` STRING COMMENT 'The data communication protocol used by the smart meter to transmit readings to the building management system or energy monitoring platform (e.g., BACnet, Modbus, DLMS/COSEM). Relevant only for smart/AMI meters; null or none for manually read meters. [ENUM-REF-CANDIDATE: Modbus|BACnet|DLMS_COSEM|ZigBee|LoRaWAN|pulse|none|other — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this energy meter master record was first created in the system. Supports data lineage, audit trail, and record lifecycle management in the lakehouse silver layer.',
    `decommission_date` DATE COMMENT 'The date the meter was taken out of service. Null for active meters. Used to close out utility accounts, finalize billing periods, and update ESG reporting boundaries.',
    `dial_digits` STRING COMMENT 'Number of digits on the meter register dial. Used to detect meter rollover (when the reading resets to zero after reaching maximum) and ensure accurate consumption calculation between consecutive reads.',
    `energy_star_property_code` STRING COMMENT 'The property identifier in the EPA ENERGY STAR Portfolio Manager platform to which this meters consumption data is reported. Enables automated data push for energy benchmarking, ENERGY STAR certification, and regulatory benchmarking compliance (e.g., NYC Local Law 84).',
    `esg_tracked` BOOLEAN COMMENT 'Indicates whether consumption data from this meter is included in the portfolios ESG reporting boundary for greenhouse gas emissions, energy intensity, and sustainability benchmarking (e.g., ENERGY STAR, GRESB, LEED).',
    `floor_number` STRING COMMENT 'The floor level within the building where the meter is physically installed. Used for spatial cost allocation, tenant submeter mapping, and building systems analysis.',
    `installation_date` DATE COMMENT 'The date the meter was physically installed at the property. Used to establish the start of the meters data history, warranty tracking, and asset lifecycle management.',
    `is_smart_meter` BOOLEAN COMMENT 'Indicates whether the meter is an Advanced Metering Infrastructure (AMI) smart meter capable of automated, interval-based data transmission. Drives data ingestion pipeline routing and enables real-time energy monitoring and demand response programs.',
    `last_calibration_date` DATE COMMENT 'Date the meter was last calibrated or tested for accuracy. Supports preventive maintenance scheduling, regulatory compliance with utility measurement standards, and data quality assurance for energy benchmarking.',
    `last_read_date` DATE COMMENT 'The date of the most recent meter reading recorded for this meter. Used to identify stale or missing reads, trigger alerts for data collection failures, and support billing cycle management.',
    `last_read_value` DECIMAL(18,2) COMMENT 'The most recent consumption reading recorded for this meter, expressed in the meters unit of measure. Used as the baseline for the next billing period calculation and for detecting anomalous consumption spikes.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this energy meter master record was most recently modified. Used for change data capture, incremental ETL processing, and audit compliance.',
    `location_description` STRING COMMENT 'Free-text description of the physical installation location of the meter within the building (e.g., Electrical Room B2, Panel MDP-1, Roof Level — HVAC Unit 3). Supports field technician dispatch and maintenance work orders.',
    `manufacturer` STRING COMMENT 'Name of the company that manufactured the meter (e.g., Landis+Gyr, Itron, Elster, Badger Meter). Used for warranty management, spare parts procurement, and vendor performance tracking.',
    `meter_name` STRING COMMENT 'Human-readable descriptive label for the meter (e.g., Main Electric Panel — Tower A, Gas Meter — Basement Boiler Room). Used in operational dashboards, work orders, and tenant utility billing reports.',
    `meter_number` STRING COMMENT 'The externally-known unique identifier assigned to the meter by the utility provider or the property management system. Used for utility billing reconciliation, provider correspondence, and field identification.',
    `meter_status` STRING COMMENT 'Current operational lifecycle status of the meter. Drives inclusion in active utility billing runs, ESG reporting, and preventive maintenance scheduling.. Valid values are `active|inactive|decommissioned|pending_installation|under_maintenance`',
    `meter_subtype` STRING COMMENT 'Further classification of the meter within its type, distinguishing main utility meters from submeters used for tenant-level cost allocation, check meters for validation, or smart/interval meters for real-time monitoring. [ENUM-REF-CANDIDATE: main|submeter|check_meter|interval|smart|pulse|other — promote to reference product]',
    `meter_type` STRING COMMENT 'Classification of the utility commodity measured by this meter. Drives cost allocation methodology, ESG reporting categories, and benchmarking peer groups. [ENUM-REF-CANDIDATE: electric|gas|water|steam|chilled_water|solar|other — promote to reference product]',
    `model_number` STRING COMMENT 'Manufacturers model designation for the meter. Used for procurement of compatible parts, firmware updates, and technical support escalation.',
    `multiplier` DECIMAL(18,2) COMMENT 'The demand multiplier or meter constant applied to raw dial readings to calculate actual consumption. Common for high-voltage or high-volume meters where the dial registers a fraction of actual usage. Critical for accurate billing and ESG reporting.',
    `next_calibration_due_date` DATE COMMENT 'Scheduled date for the next meter calibration or accuracy test. Drives preventive maintenance work order generation and ensures continuous compliance with utility measurement standards.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special instructions, or known issues related to this meter (e.g., Meter located behind locked panel — contact building engineer, Pending replacement Q3 2025). Used by facility operations and maintenance teams.',
    `read_frequency` STRING COMMENT 'The scheduled frequency at which meter readings are collected, either automatically via AMI/smart meter or manually by a technician. Drives data ingestion scheduling, billing cycle alignment, and energy benchmarking cadence.. Valid values are `hourly|daily|weekly|monthly|quarterly|on_demand`',
    `read_method` STRING COMMENT 'Method by which meter readings are obtained. Automatic reads come from AMI/smart meter telemetry; manual reads are recorded by field technicians; estimated reads are utility-provider projections; remote reads use utility provider remote access.. Valid values are `automatic|manual|estimated|remote`',
    `serial_number` STRING COMMENT 'Manufacturer-assigned unique serial number for the physical meter device. Used for warranty claims, regulatory certification tracking, and field identification during maintenance.',
    `unit_of_measure` STRING COMMENT 'The standard unit in which consumption is measured and reported for this meter (e.g., kWh for electricity, therms or CCF for gas, gallons for water, lbs or MMBTU for steam). Essential for energy benchmarking, ESG reporting, and utility cost normalization. [ENUM-REF-CANDIDATE: kWh|therms|CCF|gallons|liters|lbs|MMBTU|kW|other — promote to reference product]',
    `utility_account_number` STRING COMMENT 'The account number assigned by the utility provider for billing and service correspondence. Confidential business identifier used to match utility invoices in Accounts Payable and reconcile consumption charges.',
    `utility_provider_name` STRING COMMENT 'Name of the utility company or energy supplier providing the commodity measured by this meter (e.g., Con Edison, National Grid, LADWP). Used for vendor management, invoice matching, and utility contract administration.',
    `utility_rate_schedule` STRING COMMENT 'The tariff or rate schedule code assigned by the utility provider (e.g., SC-9, General Service Large). Determines the billing rate structure applied to consumption readings and is critical for utility cost forecasting and OPEX budgeting.',
    `warranty_expiry_date` DATE COMMENT 'Date on which the manufacturers warranty for the meter expires. Used to determine whether repair or replacement costs are recoverable under warranty and to plan capital replacement budgets.',
    `yardi_meter_code` STRING COMMENT 'The meter identifier in Yardi Voyager used for utility billing and accounts payable invoice matching. Enables cross-system reconciliation between the CMMS meter record and the property accounting system.',
    CONSTRAINT pk_energy_meter PRIMARY KEY(`energy_meter_id`)
) COMMENT 'Master record for utility meters and energy monitoring devices installed at managed properties — electric, gas, water, and steam meters. Captures meter ID, meter type, utility provider account number, installation location (building, floor, unit), read frequency, and current status. Supports utility cost allocation, energy benchmarking, and sustainability reporting.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`asset_service_coverage` (
    `asset_service_coverage_id` BIGINT COMMENT 'Unique surrogate identifier for each asset-contract coverage record',
    `building_asset_id` BIGINT COMMENT 'Foreign key linking to the specific building asset covered under this service contract',
    `service_contract_id` BIGINT COMMENT 'Foreign key linking to the service contract providing coverage for this asset',
    `added_to_contract_date` DATE COMMENT 'Date this asset was formally added to the service contract scope. Used for contract amendment tracking and billing reconciliation when assets are added mid-term.',
    `asset_specific_sla_hours` DECIMAL(18,2) COMMENT 'Response time SLA in hours specific to this asset under this contract. May override the contract-level SLA for critical assets (e.g., life safety systems, data center cooling) that require faster response than the standard contract terms.',
    `coverage_end_date` DATE COMMENT 'Date on which coverage for this specific asset under this contract ends. May differ from contract expiration if asset is removed, replaced, or transferred.',
    `coverage_notes` STRING COMMENT 'Free-text notes documenting special terms, exclusions, or conditions specific to this assets coverage under this contract (e.g., Excludes compressor replacement, Requires 24-hour notice for access).',
    `coverage_scope` STRING COMMENT 'Specific scope of service coverage for this asset under this contract. Defines what types of maintenance activities are covered (full service, PM only, emergency repairs, parts replacement, labor, or custom terms).',
    `coverage_start_date` DATE COMMENT 'Date on which this specific asset became covered under this service contract. May differ from contract commencement if assets are added mid-term.',
    `coverage_status` STRING COMMENT 'Current operational status of coverage for this asset under this contract. Active = currently covered; suspended = temporarily not covered (e.g., asset offline for renovation); expired = coverage period ended; terminated = coverage cancelled before end date.',
    `is_primary_contract` BOOLEAN COMMENT 'Flag indicating whether this is the primary service contract for this asset. Used when an asset has overlapping coverage (e.g., manufacturer warranty + independent maintenance contract) to designate the first-call service provider.',
    `removed_from_contract_date` DATE COMMENT 'Date this asset was formally removed from the service contract scope. Null if asset remains covered. Used for contract amendment tracking and billing adjustments.',
    CONSTRAINT pk_asset_service_coverage PRIMARY KEY(`asset_service_coverage_id`)
) COMMENT 'This association product represents the contractual coverage relationship between building assets and maintenance service contracts. It captures which specific assets are covered under which service agreements, with coverage-specific terms that exist only in the context of this relationship. Each record links one building asset to one service contract with attributes defining the scope, duration, and service level commitments for that specific asset under that specific contract.. Existence Justification: In real estate facility management, building assets routinely have overlapping service coverage from multiple contracts (manufacturer warranty service, independent maintenance agreements, specialized system contracts), and service contracts routinely cover dozens to hundreds of individual assets across properties. The service_contract.covered_equipment_description STRING field is a denormalized representation that cannot support asset-specific coverage terms, SLAs, or coverage history tracking.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`asset_coverage_schedule` (
    `asset_coverage_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for each asset-coverage schedule record',
    `building_asset_id` BIGINT COMMENT 'Foreign key linking to the specific building equipment or infrastructure asset being scheduled on this coverage line',
    `coverage_id` BIGINT COMMENT 'Foreign key linking to the insurance coverage line under which this asset is scheduled',
    `asset_specific_deductible` DECIMAL(18,2) COMMENT 'Deductible amount applicable to claims involving this specific asset under this coverage line. May differ from the coverage lines standard deductible_amount if the asset has a higher-risk profile or negotiated terms. Null if the coverage lines standard deductible applies.',
    `asset_specific_limit` DECIMAL(18,2) COMMENT 'Maximum payout limit for claims involving this specific asset under this coverage line. May differ from the coverage lines overall coverage_limit if the asset has a sub-limit or enhanced limit. Null if the coverage lines standard limit applies.',
    `endorsement_number` STRING COMMENT 'Identifier of the policy endorsement that added or modified this assets schedule entry on this coverage line. Null if the asset was included in the original policy schedule.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent insurance carrier inspection or risk assessment conducted specifically for this asset under this coverage line. Used to track compliance with underwriter-required inspection schedules.',
    `next_inspection_due_date` DATE COMMENT 'Date by which the next insurance carrier inspection or risk assessment is required for this asset under this coverage line to maintain coverage. Null if no periodic inspection is required.',
    `schedule_effective_date` DATE COMMENT 'Date on which this asset was added to this coverage line schedule and became covered. May differ from the coverage lines overall effective_date if the asset was added mid-term via endorsement.',
    `schedule_expiration_date` DATE COMMENT 'Date on which this assets coverage under this specific coverage line expires. May differ from the coverage lines overall expiration_date if the asset was removed mid-term or if coverage was non-renewed for this asset only.',
    `schedule_notes` STRING COMMENT 'Free-text notes documenting special conditions, underwriter requirements, or risk mitigation measures specific to this assets coverage under this line (e.g., Requires annual boiler inspection by licensed engineer, Coverage contingent on sprinkler system maintenance).',
    `schedule_status` STRING COMMENT 'Current status of this assets inclusion on this coverage line schedule. active = currently covered; expired = coverage period ended; pending = endorsement submitted but not yet effective; cancelled = removed mid-term; excluded = explicitly excluded from coverage via endorsement.',
    `scheduled_insured_value` DECIMAL(18,2) COMMENT 'The specific insured value assigned to this building asset on this coverage line. May differ from the assets replacement_cost based on agreed value endorsements, depreciation schedules, or coverage-specific valuation methods. This is the amount used for premium calculation and loss settlement for this asset under this coverage.',
    `valuation_method` STRING COMMENT 'Basis on which this assets insured value and loss settlement are calculated under this coverage line. May differ from the coverage lines overall valuation_basis if the asset has specific endorsements (e.g., agreed value for a historic boiler, ACV for an aging chiller).',
    CONSTRAINT pk_asset_coverage_schedule PRIMARY KEY(`asset_coverage_schedule_id`)
) COMMENT 'This association product represents the scheduled insurance coverage relationship between building assets and insurance coverage lines. In real estate insurance, major building equipment (boilers, chillers, elevators, HVAC systems) are individually scheduled on equipment breakdown, boiler and machinery, or inland marine coverage lines. Each record captures the insured value, deductible, coverage limits, and effective dates specific to that asset-coverage pairing. A single building asset may appear on multiple coverage lines across different policy years or coverage types, and a single coverage line may schedule multiple high-value assets. This is the operational record used by risk managers to verify adequate coverage per asset and by claims adjusters to determine coverage applicability.. Existence Justification: In real estate insurance operations, high-value building equipment (boilers, chillers, elevators, HVAC systems, generators) are individually scheduled on equipment breakdown, boiler and machinery, or inland marine coverage lines. A single building asset can appear on multiple coverage lines across different policy years, coverage types, or insurers, and a single coverage line typically schedules multiple assets. Risk managers actively manage these schedules, assigning insured values, deductibles, and effective dates specific to each asset-coverage pairing.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`parts_usage` (
    `parts_usage_id` BIGINT COMMENT 'Unique system-generated identifier for each parts usage transaction record',
    `parts_inventory_id` BIGINT COMMENT 'Foreign key linking to the parts inventory item consumed in this usage transaction',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to the work order against which parts were issued',
    `cost_classification` STRING COMMENT 'Accounting classification indicating whether this specific parts usage is capitalized as a capital expenditure (CAPEX) or expensed as an operating expenditure (OPEX). May differ from the parts default classification based on the nature of the work order.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the unit_cost_at_issuance is denominated. Inherited from the parts_inventory record at time of issuance.',
    `issued_by` STRING COMMENT 'Name or identifier of the technician, warehouse staff, or system user who issued the part to the work order. Supports audit trail and accountability for inventory transactions.',
    `issued_date` DATE COMMENT 'The date on which the part was physically issued from inventory and allocated to the work order. Critical for inventory transaction history and work order timeline tracking.',
    `quantity_issued` DECIMAL(18,2) COMMENT 'The quantity of the part issued from inventory to fulfill the work order, expressed in the parts unit of measure. This is relationship-specific data that represents the consumption amount for this specific work order.',
    `returned_quantity` DECIMAL(18,2) COMMENT 'The quantity of the part that was returned to inventory after being issued to the work order (e.g., unused surplus). Enables accurate net consumption calculation and inventory reconciliation.',
    `unit_cost_at_issuance` DECIMAL(18,2) COMMENT 'The cost per unit of the part at the time it was issued to the work order. Captures historical cost for accurate work order costing, as the current unit_cost in parts_inventory may change over time.',
    CONSTRAINT pk_parts_usage PRIMARY KEY(`parts_usage_id`)
) COMMENT 'This association product represents the consumption of maintenance parts against work orders in facility operations. It captures the operational event of issuing inventory items to fulfill maintenance work. Each record links one parts_inventory item to one work_order with attributes that exist only in the context of this consumption transaction: quantity issued, unit cost at time of issuance, issue date, returned quantity, and cost classification.. Existence Justification: In facility maintenance operations, parts usage represents the operational event of consuming inventory items to fulfill work orders. A single work order routinely requires multiple different parts (e.g., HVAC repair needs filters, belts, refrigerant), and a single part type is consumed across many different work orders over time. CMMS platforms like Building Engines explicitly model this as a parts usage or materials used transaction entity with its own attributes (quantity, cost at issuance, date, returns).';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`warehouse` (
    `warehouse_id` BIGINT COMMENT 'Primary key for warehouse',
    `parent_warehouse_id` BIGINT COMMENT 'Self-referencing FK on warehouse (parent_warehouse_id)',
    `address_line_1` STRING COMMENT 'Primary street address line of the warehouse facility location.',
    `address_line_2` STRING COMMENT 'Secondary address line for suite, building, or unit information of the warehouse facility.',
    `annual_lease_cost` DECIMAL(18,2) COMMENT 'Total annual lease cost for the warehouse facility in the operating currency, if leased.',
    `certification_status` STRING COMMENT 'Current status of industry or regulatory certifications held by the warehouse facility.',
    `city` STRING COMMENT 'City or municipality where the warehouse facility is located.',
    `climate_controlled` BOOLEAN COMMENT 'Indicates whether the warehouse has climate control systems for temperature and humidity regulation.',
    `commissioning_date` DATE COMMENT 'Date when the warehouse facility was first commissioned and became operational.',
    `country_code` STRING COMMENT 'Three-letter ISO country code where the warehouse is located.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the warehouse record was first created in the system.',
    `decommissioning_date` DATE COMMENT 'Date when the warehouse facility was decommissioned and ceased operations, if applicable.',
    `email_address` STRING COMMENT 'Primary email address for warehouse facility communications and operational inquiries.',
    `energy_efficiency_rating` STRING COMMENT 'Energy efficiency rating of the warehouse facility based on building performance assessments.',
    `environmental_compliance` BOOLEAN COMMENT 'Indicates whether the warehouse facility meets all applicable environmental regulations and standards.',
    `fire_suppression_system` STRING COMMENT 'Type of fire suppression system installed in the warehouse for fire safety compliance.',
    `hazmat_storage_approved` BOOLEAN COMMENT 'Indicates whether the warehouse is approved and equipped for storage of hazardous materials.',
    `insurance_policy_number` STRING COMMENT 'Policy number for the property and liability insurance coverage for the warehouse facility.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent safety, compliance, or operational inspection conducted at the warehouse facility.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when the warehouse record was last updated or modified in the system.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate of the warehouse facility in decimal degrees.',
    `lease_expiration_date` DATE COMMENT 'Date when the current lease agreement for the warehouse facility expires, if applicable.',
    `lease_ownership_status` STRING COMMENT 'Indicates whether the warehouse facility is owned by the company or leased from a third party.',
    `loading_docks_count` STRING COMMENT 'Number of loading dock bays available at the warehouse for inbound and outbound shipments.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate of the warehouse facility in decimal degrees.',
    `manager_name` STRING COMMENT 'Full name of the warehouse manager or facility operations lead responsible for day-to-day operations.',
    `next_inspection_due_date` DATE COMMENT 'Scheduled date for the next required safety, compliance, or operational inspection of the warehouse facility.',
    `notes` STRING COMMENT 'Additional notes, comments, or special instructions related to the warehouse facility operations or characteristics.',
    `operating_hours` STRING COMMENT 'Standard operating hours for the warehouse facility, including shift schedules and availability windows.',
    `operational_status` STRING COMMENT 'Current operational state of the warehouse facility in its lifecycle.',
    `parking_spaces_count` STRING COMMENT 'Total number of parking spaces available at the warehouse facility for employees and visitors.',
    `phone_number` STRING COMMENT 'Primary contact phone number for the warehouse facility operations.',
    `postal_code` STRING COMMENT 'Postal or ZIP code for the warehouse facility address.',
    `property_tax_annual` DECIMAL(18,2) COMMENT 'Annual property tax liability for the warehouse facility in the operating currency.',
    `security_level` STRING COMMENT 'Classification of physical security measures and access controls implemented at the warehouse facility.',
    `state_province` STRING COMMENT 'State, province, or administrative region where the warehouse is located.',
    `storage_capacity_sqft` DECIMAL(18,2) COMMENT 'Usable storage area within the warehouse measured in square feet, excluding office and common areas.',
    `temperature_range_max_f` DECIMAL(18,2) COMMENT 'Maximum temperature threshold maintained in the warehouse facility, measured in degrees Fahrenheit.',
    `temperature_range_min_f` DECIMAL(18,2) COMMENT 'Minimum temperature threshold maintained in the warehouse facility, measured in degrees Fahrenheit.',
    `total_area_sqft` DECIMAL(18,2) COMMENT 'Total floor area of the warehouse facility measured in square feet, including storage, office, and operational spaces.',
    `warehouse_code` STRING COMMENT 'Externally-known unique alphanumeric code assigned to the warehouse for identification in operational systems and documentation.',
    `warehouse_name` STRING COMMENT 'Human-readable name or designation of the warehouse facility.',
    `warehouse_type` STRING COMMENT 'Classification of the warehouse based on its primary operational function and storage characteristics.',
    CONSTRAINT pk_warehouse PRIMARY KEY(`warehouse_id`)
) COMMENT 'Master reference table for warehouse. Referenced by warehouse_id.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`maintenance`.`hvac_zone` (
    `hvac_zone_id` BIGINT COMMENT 'Primary key for hvac_zone',
    `parent_hvac_zone_id` BIGINT COMMENT 'Self-referencing FK on hvac_zone (parent_hvac_zone_id)',
    `air_changes_per_hour` DECIMAL(18,2) COMMENT 'Number of times the total air volume in the zone is replaced per hour, critical for ventilation requirements.',
    `air_handler_unit_id` BIGINT COMMENT 'Reference to the primary air handler unit serving this HVAC zone.',
    `area_square_feet` DECIMAL(18,2) COMMENT 'Total floor area of the HVAC zone measured in square feet.',
    `building_id` BIGINT COMMENT 'Reference to the building that contains this HVAC zone.',
    `commissioning_date` DATE COMMENT 'Date when the HVAC zone was originally commissioned and put into service.',
    `compliance_certification` STRING COMMENT 'Environmental or energy efficiency certification status applicable to this HVAC zone.',
    `control_system_type` STRING COMMENT 'Type of control system managing the HVAC zone (BMS=Building Management System, DDC=Direct Digital Control).',
    `cooling_load_btu_per_hour` DECIMAL(18,2) COMMENT 'Design cooling load capacity required for the zone measured in BTU per hour.',
    `cost_center_code` STRING COMMENT 'Accounting cost center code for tracking OPEX expenses related to this HVAC zone.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the HVAC zone record was first created in the system.',
    `demand_control_ventilation_enabled` BOOLEAN COMMENT 'Indicates whether demand-controlled ventilation based on occupancy or CO2 levels is enabled.',
    `design_temperature_cooling_f` DECIMAL(18,2) COMMENT 'Target cooling temperature setpoint for the zone in degrees Fahrenheit.',
    `design_temperature_heating_f` DECIMAL(18,2) COMMENT 'Target heating temperature setpoint for the zone in degrees Fahrenheit.',
    `energy_recovery_enabled` BOOLEAN COMMENT 'Indicates whether energy recovery ventilation is enabled for this zone to improve efficiency.',
    `fire_smoke_damper_count` STRING COMMENT 'Number of fire and smoke dampers installed in the zone for life safety compliance.',
    `floor_number` STRING COMMENT 'Floor number where the HVAC zone is located. Negative values indicate basement levels.',
    `heating_load_btu_per_hour` DECIMAL(18,2) COMMENT 'Design heating load capacity required for the zone measured in BTU per hour.',
    `humidity_setpoint_percent` DECIMAL(18,2) COMMENT 'Target relative humidity level for the zone expressed as a percentage.',
    `last_balancing_date` DATE COMMENT 'Date when the HVAC zone last underwent air balancing and commissioning to ensure proper airflow distribution.',
    `last_modified_date` DATE COMMENT 'Date when the HVAC zone configuration or parameters were last updated in the system.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when the HVAC zone record was last updated in the system.',
    `maintenance_priority` STRING COMMENT 'Priority level for preventive maintenance and service requests for this zone.',
    `next_balancing_due_date` DATE COMMENT 'Scheduled date for the next air balancing service for the zone.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, special requirements, or zone-specific instructions.',
    `occupancy_capacity` STRING COMMENT 'Maximum number of occupants the HVAC zone is designed to support for load calculations.',
    `operating_schedule` STRING COMMENT 'Standard operating schedule pattern for the HVAC zone defining when conditioning is required.',
    `tenant_id` BIGINT COMMENT 'Reference to the tenant occupying this HVAC zone, if applicable for tenant-specific climate control.',
    `thermostat_count` STRING COMMENT 'Number of thermostats installed in the zone for temperature monitoring and control.',
    `vav_box_count` STRING COMMENT 'Number of VAV boxes installed in the zone for air distribution control.',
    `ventilation_rate_cfm` DECIMAL(18,2) COMMENT 'Required outdoor air ventilation rate for the zone measured in cubic feet per minute.',
    `zone_code` STRING COMMENT 'Business identifier code for the HVAC zone, used for operational reference and system integration.',
    `zone_description` STRING COMMENT 'Detailed description of the HVAC zone including location details, boundaries, and special characteristics.',
    `zone_name` STRING COMMENT 'Human-readable name of the HVAC zone (e.g., North Wing Floor 3, Lobby Area).',
    `zone_status` STRING COMMENT 'Current operational status of the HVAC zone in the building management system.',
    `zone_type` STRING COMMENT 'Classification of the HVAC zone based on its primary use and occupancy type.',
    CONSTRAINT pk_hvac_zone PRIMARY KEY(`hvac_zone_id`)
) COMMENT 'Master reference table for hvac_zone. Referenced by hvac_zone_id.';

